// Settings drawer: a right-edge slide-out panel for scene-level options that
// aren't tree parameters. Currently holds the optional environmental backdrops
// (distant mountains + forest); add future scene toggles here.
//
// Mirrors gallery.js: owns its own open/close state and registers window.*
// handlers for the inline onclick attributes in index.html. main.js does a
// side-effect `import './settings.js'` to wire these up.

import { setMountainsVisible, setForestVisible, setPagodaVisible, setCourtyardVisible, setLanternVisible, setToriiVisible, setShortLanternVisible, setWaterCanVisible, setGravelDark } from './environment.js';

let isSettingsOpen = false;

window.toggleSettings = function () {
  const drawer = document.getElementById('settingsDrawer');
  if (!drawer) return;
  isSettingsOpen = !isSettingsOpen;
  drawer.classList.toggle('open', isSettingsOpen);
};

// Close the drawer when clicking anywhere outside it. Ignores clicks on the
// gear button (its own onclick handles toggling) and clicks inside the drawer.
function initOutsideClickClose() {
  document.addEventListener('pointerdown', (e) => {
    if (!isSettingsOpen) return;
    const drawer = document.getElementById('settingsDrawer');
    const gear = document.getElementById('settings-button');
    if (drawer?.contains(e.target) || gear?.contains(e.target)) return;
    isSettingsOpen = false;
    drawer?.classList.remove('open');
  });
}

// Zen mode: strip the screen down to just the bonsai. Adds `zen-mode` to <body>
// (CSS hides every chrome element and reveals the lone #zen-exit-button) and
// closes the settings drawer first so it isn't left half-open underneath.
window.enterZenMode = function () {
  isSettingsOpen = false;
  document.getElementById('settingsDrawer')?.classList.remove('open');
  document.body.classList.add('zen-mode');
};

window.exitZenMode = function () {
  document.body.classList.remove('zen-mode');
};

// Inline SVG icons for the corner button. Unicode has no reliable "exit
// fullscreen" glyph (the window-control codepoints render as tofu on many
// systems), so we draw the corner-bracket expand/compress icons ourselves —
// no dependency, identical on every platform. Stroke inherits the button color.
const svgIcon = (paths) =>
  `<svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor"` +
  ` stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">${paths}</svg>`;

// Outward corner brackets (enter fullscreen).
const ENTER_ICON = svgIcon(
  '<path d="M8 3H5a2 2 0 0 0-2 2v3"/><path d="M21 8V5a2 2 0 0 0-2-2h-3"/>' +
  '<path d="M3 16v3a2 2 0 0 0 2 2h3"/><path d="M16 21h3a2 2 0 0 0 2-2v-3"/>'
);
// Inward corner brackets (exit fullscreen).
const EXIT_ICON = svgIcon(
  '<path d="M8 3v3a2 2 0 0 1-2 2H3"/><path d="M21 8h-3a2 2 0 0 1-2-2V3"/>' +
  '<path d="M3 16h3a2 2 0 0 1 2 2v3"/><path d="M16 21v-3a2 2 0 0 1 2-2h3"/>'
);

// Fullscreen toggle for the corner button. Requests fullscreen on the page root
// (document.documentElement) and exits if already fullscreen.
window.toggleFullscreen = function () {
  if (!document.fullscreenElement) {
    document.documentElement.requestFullscreen?.();
  } else {
    document.exitFullscreen?.();
  }
};

// Keep the icon in sync with the actual fullscreen state — covers exiting via
// Esc / browser chrome, not just our button.
function refreshFullscreenButton() {
  const btn = document.getElementById('fullscreen-button');
  if (!btn) return;
  btn.innerHTML = document.fullscreenElement ? EXIT_ICON : ENTER_ICON;
}

// The Fullscreen API is unsupported on some browsers (notably iOS Safari, which
// exposes no requestFullscreen on elements). Hide the button there rather than
// showing a dead control.
function initFullscreenButton() {
  const btn = document.getElementById('fullscreen-button');
  if (!btn) return;
  const supported = !!document.documentElement.requestFullscreen;
  if (!supported) {
    btn.style.display = 'none';
    return;
  }
  document.addEventListener('fullscreenchange', refreshFullscreenButton);
  refreshFullscreenButton();
}

// Each scene toggle: its checkbox id paired with the setter it drives.
const SCENE_TOGGLES = [
  ['toggleMountains', setMountainsVisible],
  ['toggleForest', setForestVisible],
  ['togglePagoda', setPagodaVisible],
  ['toggleCourtyard', setCourtyardVisible],
  ['toggleLantern', setLanternVisible],
  ['toggleShortLantern', setShortLanternVisible],
  ['toggleTorii', setToriiVisible],
  ['toggleWaterCan', setWaterCanVisible],
  ['toggleGravelDark', setGravelDark],
];

// Wire the scene checkboxes once the DOM is ready (listeners only — no scene
// access here, since this runs before the scene is built).
function initSettings() {
  for (const [id, setter] of SCENE_TOGGLES) {
    const el = document.getElementById(id);
    if (el) el.addEventListener('change', (e) => setter(e.target.checked));
  }

  initFullscreenButton();
  initOutsideClickClose();
}

// Make the checkboxes authoritative once the scene exists. Browsers restore a
// checkbox's checked state across reloads, but the scene always rebuilds fresh
// (everything off) — so a restored "checked" box would show on while its model
// is absent, and the first click would just toggle it back off (the "click
// twice" bug). Applying each box's current state here syncs the scene to the UI
// and brings restored selections back without a click. Called from main.js after
// createEnvironment(), so app.scene/app.backdrops are ready.
export function syncSceneToggles() {
  for (const [id, setter] of SCENE_TOGGLES) {
    const el = document.getElementById(id);
    if (el) setter(el.checked);
  }
}

// ===========================================
// SHARE HOOKS (consumed by shareBonsai.js)
// ===========================================
// So a shared link reproduces the scenery too, not just the tree. settings owns
// "which decor is on <-> the scene"; shareBonsai composes this with the tree
// payload. Neither this module nor gallery needs to know about the other.

// Just the enabled toggle ids — absent ones default off on the recipient's fresh
// scene, so the payload stays tiny (and is self-describing / order-independent,
// surviving any future reordering of SCENE_TOGGLES).
export function captureSceneToggles() {
  return SCENE_TOGGLES
    .filter(([id]) => document.getElementById(id)?.checked)
    .map(([id]) => id);
}

// Drive both the checkboxes and the scene from an enabled-id list. Sets each
// box's checked state *and* calls its setter (like syncSceneToggles), so the
// settings drawer reflects the shared selection and there's no "click twice" bug.
export function applySceneToggles(enabledIds) {
  const on = new Set(enabledIds || []);
  for (const [id, setter] of SCENE_TOGGLES) {
    const checked = on.has(id);
    const el = document.getElementById(id);
    if (el) el.checked = checked;
    setter(checked);
  }
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initSettings);
} else {
  initSettings();
}
