      // isn't obvious from the raw geometry. Measure the actual bounding box and
      // scale to a target height, then seat it on the ground — no magic numbers.
      const targetHeight = 190; // world units; a gateway taller than the bonsai
      const box = new THREE.Box3().setFromObject(model);
