// Settings-drawer toggle: darken the zen-garden gravel. The gravel plane's
// material color multiplies its texture map, so we stash the original color once
// and swap to a darker gray, restoring the original when turned off.
function setGravelDark(dark) {
  gravelDark = dark;
  if (!gravel) return;
  const mat = gravel.material;
  if (!mat.userData.originalColor) mat.userData.originalColor = mat.color.clone();
  if (dark) mat.color.setHex(0x494b4d);
  else mat.color.copy(mat.userData.originalColor);
}

    function addZenGardenRocks() {
  const zenGroup = new THREE.Group();

  const rockMaterial = new THREE.MeshStandardMaterial({
    color: 0x5f5f5f,
    roughness: 0.9,
    flatShading: true,
  });

  // Helper to sculpt an organic but solid rock
  function makeZenRock(size = 12, stretch = [1, 1, 1]) {
    const geo = new THREE.IcosahedronGeometry(size, 1); // low poly, but smooth
    const pos = geo.attributes.position;

    // Slightly shift vertices for a natural look
    for (let i = 0; i < pos.count; i++) {
      const x = pos.getX(i);
      const y = pos.getY(i);
      const z = pos.getZ(i);

      // Gentle, not noisy: push vertices outward a little
      const scale = 1 + (Math.sin(x * 0.5 + z) * 0.08 + Math.cos(y * 0.3) * 0.05);
      pos.setXYZ(i, x * scale * stretch[0], y * scale * stretch[1], z * scale * stretch[2]);
    }
    geo.computeVertexNormals();
    return new THREE.Mesh(geo, rockMaterial);
  }

  // A few deliberate, "epic" stones
  const placements = [
    { x: -270, z: -180, y: -30, size: 14, stretch: [1.6, 0.8, 1.1] },
    { x: -290, z: -140, y: -10, size: 12, stretch: [1, 2.4, 1] },
    { x: -240, z: 80, y: -5, size: 16, stretch: [1.2, 1, 0.9] },
    { x: 290, z: 150, y: -45, size: 22, stretch: [1, 1.4, 1] },
    { x: 240, z: 180, y: -15, size: 16, stretch: [1.8, 1, 0.9] },
  ];

  placements.forEach(p => {
    const rock = makeZenRock(p.size, p.stretch);
    rock.position.set(p.x, -25, p.z);
    rock.rotation.y = Math.random() * Math.PI;
    rock.castShadow = true;
    rock.receiveShadow = true;
    zenGroup.add(rock);
  });

  app.scene.add(zenGroup);
  zenRocksGroup = zenGroup; // kept so winter mode can frost the rock tops
}

