// add a dismiss button to the instructions
document.getElementById('instructions').addEventListener('click', function() {
  document.getElementById('instructions').style.display = 'none';
});

//hide controls
function hideControls() {
  document.getElementById('controls').style.display = 'none';
}

//show controls
function showControls() {
  document.getElementId('control-col').style.display = 'flex';
}

// Mobile bottom sheets: two accordion panels (Trunk / Foliage) share one slot. The
// open section is a class on #control-col — 'sheet-trunk', 'sheet-foliage', or
// neither. Opening one closes the other, so only ~25% of the screen is ever covered.
const SHEET_CLASS = { trunk: 'sheet-trunk', foliage: 'sheet-foliage' };

// Open the given section (closing the other), or pass null/falsy to close both.
function openSheet(section) {
  const col = document.getElementById('control-col');
  col.classList.toggle('sheet-trunk', section === 'trunk');
  col.classList.toggle('sheet-foliage', section === 'foliage');
}
window.closeControlSheet = function () { openSheet(null); };

// Back-compat shim for any caller still toggling the old single sheet: open Trunk
// if nothing is open, otherwise close.
window.toggleControlSheet = function () {
  const col = document.getElementById('control-col');
  const open = col.classList.contains('sheet-trunk') || col.classList.contains('sheet-foliage');
  openSheet(open ? null : 'trunk');
};

// Drive each tab handle: a vertical swipe is directional (up opens that section,
// down closes), while a near-stationary press is a tap that toggles it. We resolve
// on pointerup rather than live-tracking the finger because open/closed is a CSS
// class (max-height transition), not a transform.
function initSheetGestures() {
  const col = document.getElementById('control-col');
  const tabs = document.querySelectorAll('.sheet-tab');
  if (!col || !tabs.length) return;

  const SWIPE_THRESHOLD = 28; // px of vertical travel before it counts as a swipe

  tabs.forEach((tab) => {
    const section = tab.dataset.sheet; // 'trunk' | 'foliage'
    let startY = 0;
    let dragging = false;

    tab.addEventListener('pointerdown', (e) => {
      dragging = true;
      startY = e.clientY;
      tab.setPointerCapture(e.pointerId);
    });

    tab.addEventListener('pointerup', (e) => {
      if (!dragging) return;
      dragging = false;
      const dy = e.clientY - startY;
      if (Math.abs(dy) >= SWIPE_THRESHOLD) {
        openSheet(dy < 0 ? section : null); // up → open this one, down → close
      } else {
        const isOpen = col.classList.contains(SHEET_CLASS[section]);
        openSheet(isOpen ? null : section); // tap → toggle this one
      }
    });

    tab.addEventListener('pointercancel', () => { dragging = false; });
  });
}

initSheetGestures();