 import * as THREE from 'three';
 import { Sky } from 'three/addons/objects/Sky.js';
 import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
 import { parameters, app } from './core.js';
 import { createEnvironment } from './environment.js';
 import { initInteraction } from './interaction.js';
 import { setupControls } from './ui-controls.js';
 import { Tree, updateFoliageWind, updateLeafFall } from './tree.js';
 import { updateWinter } from './snow.js';
 import './gallery.js'; // registers the gallery UI (window.saveBonsai, etc.)
import { loadSharedTreeFromURL } from './shareBonsai.js'; // registers window.shareBonsai + inbound share-link loading
import { syncSceneToggles } from './settings.js'; // registers the settings drawer (window.toggleSettings) + scene-toggle sync

