// tree.js — the procedural bonsai: the Tree and Branch classes.
//
// Tree builds the trunk (lathe/tapered geometry, vertex-colored bark, lean +
// noise), owns this.branches, grows main branches and sub-branches, and
// regenerates foliage. Branch attaches itself inside the trunk and builds either
// pine-needle or deciduous foliage. Both read the shared `parameters`; color
// palettes come from Colors and randomness helpers from Math2 (both in core).
// Animations use the global `gsap` (loaded via a <script> tag in index.html).
//
// Self-contained with respect to the scene graph: everything is built into
// `this.mesh` (a THREE.Group); the caller adds that group to app.scene.

import * as THREE from 'three';
import { mergeGeometries } from 'three/addons/utils/BufferGeometryUtils.js';
import { parameters, Colors, Math2, app } from './core.js';
import { createRoots } from './roots.js';

// Branch tube tessellation — must match the TubeGeometry call in
// Branch.createBranchGeometry(). The tube has BRANCH_TUBULAR_SEGMENTS segments
// (so BRANCH_TUBULAR_SEGMENTS + 1 vertex rings) along the branch curve; partial
// pruning snaps the cut to one of those rings.
const BRANCH_TUBULAR_SEGMENTS = 4;
const BRANCH_RADIAL_SEGMENTS = 8;

// A sub-branch only sprouts a third level of "twigs" once it is at least this
// thick — only the very thinnest sub-branches (which already read as twigs) are
// left bare; mid-size branches still carry a few.
const TWIG_MIN_PARENT_THICKNESS = 0.8;

// Paper-birch bark: a near-white value (not pure white, so it reads as bark, not
// paper) that also flags the trunk/branch colorers to draw the dark lenticel
// streaks below. Matched by exact value against parameters.truncColor.
const BIRCH_BARK = 0xF0EDE5;
const BIRCH_LENTICEL = new THREE.Color(0x2a2a2a);

// Dark horizontal lenticel streaks for paper birch. Given a vertex's angle
// around the trunk/branch and its 0..1 position along it, returns 0..1 darkness:
// mostly 0, with thin irregular bands that break into dashes around the
// circumference so they read as birch lenticels rather than solid rings. Pure
// function of geometry (no RNG) so it never perturbs the seeded build stream or
// replay determinism.
function birchStreak(angle, t) {
  // Two incommensurate sines -> irregularly spaced bands up the length.
  const bands = Math.sin(t * 47.0) * 0.6 + Math.sin(t * 22.3 + 1.7) * 0.4;
  // Keep only the peaks, as thin bands; everything below the threshold is bare.
  const band = (bands - 0.55) / 0.45;
  if (band <= 0) return 0;
  // Break each band into dashes around the circumference; phase drifts with
  // height so the dashes don't stack into vertical seams.
  const dash = 0.5 + 0.5 * Math.sin(angle * 3.0 + t * 60.0);
  return Math.min(1, band) * dash;
}

// Darken an already-finalized bark `color` (in place) with birch lenticel
// streaks, but only when the birch bark is selected — a no-op for every other
// trunk color. `lengthAxis` names the vertex axis running along the trunk/branch
// (trunks/main branches lathe along 'y', branch tubes run along 'z'); the other
// two axes give the angle that breaks the bands into dashes.
function applyBirchBand(color, positions, i, t, lengthAxis) {
  if (parameters.truncColor !== BIRCH_BARK) return;
  const angle = lengthAxis === 'y'
    ? Math.atan2(positions.getZ(i), positions.getX(i))
    : Math.atan2(positions.getY(i), positions.getX(i));
  const d = birchStreak(angle, t);
  if (d > 0) color.lerp(BIRCH_LENTICEL, d * 0.8);
}

// --- Foliage wind + per-instance color ------------------------------------
// Both needles and leaves are InstancedMeshes whose materials get the same two
// shader tweaks via injectFoliageShader(): (1) a per-instance `instanceColor`
// attribute multiplied into the final color (so one material draws a whole
// branch of varied foliage), and (2) a gentle wind sway driven by `uTime`.
//
// The wind uniforms are a single shared object referenced by every foliage
// material, so updateFoliageWind() (called once per frame from animate()) ticks
// the whole tree at once. uWindDir is the horizontal sway direction; uWindAmp is
// the sway magnitude per unit of height above the anchor (the shader multiplies
// it by each vertex's local height), derived from parameters.windStrength.
const windUniforms = {
  uTime: { value: 0 },
  uWindAmp: { value: 0 },
  uWindDir: { value: new THREE.Vector2(1, 0) }
};

// Push the live wind parameters into the shared uniforms. Called every frame.
export function updateFoliageWind(timeSeconds) {
  windUniforms.uTime.value = timeSeconds;
  // windStrength ~0..0.2; this is multiplied per-vertex by height above the
  // anchor in the shader, so a small factor here already gives a visible tip sway.
  windUniforms.uWindAmp.value = parameters.windStrength * 4;
  const dir = parameters.windDirection;
  windUniforms.uWindDir.value.set(dir.x, dir.z);
}

// --- Leaf/petal fall --------------------------------------------------------
// Two foliage types shed: autumn leaves flutter down a few at a time, and cherry
// blossoms are forever raining — a steady drift of single petals plus the
// occasional whole blossom. Driven once per frame from animate() via
// updateLeafFall(); it self-throttles on internal timers and is a no-op for
// every other case (and for pine, which has needles, not leaves).
let _leafFallClock = 0;            // timeSeconds at the previous tick
let _flowerTimer = 0;             // counts down to the next whole leaf/flower drop
let _petalTimer = 0;             // counts down to the next single cherry petal
const AUTUMN_FALL_INTERVAL = 1.2; // average seconds between autumn leaf drops
const CHERRY_FLOWER_INTERVAL = 1.6; // whole blossoms drop rarely...
const CHERRY_PETAL_INTERVAL = 0.4;  // ...while single petals drift down often

// What's shedding, if anything: 'cherry' (always-on petal rain) takes priority
// over 'autumn' (gradient palette). null means nothing sheds right now.
function fallMode() {
  if (isNeedleType()) return null; // conifers: needles don't shed
  if (parameters.leafType === 'none') return null; // bare tree: nothing to shed
  if (parameters.leafType === 'cherry') return 'cherry';
  if (leafPalette() === 'autumn') return 'autumn';
  return null;
}

export function updateLeafFall(timeSeconds, tree) {
  // Frame delta, clamped so a backgrounded tab doesn't dump a burst of leaves.
  const dt = _leafFallClock ? Math.min(timeSeconds - _leafFallClock, 0.1) : 0;
  _leafFallClock = timeSeconds;

  const mode = tree && fallMode();
  if (!mode) return;

  if (mode === 'autumn') {
    // Autumn leaves actually drop off, so the tree gradually thins.
    _flowerTimer -= dt;
    if (_flowerTimer <= 0) {
      _flowerTimer = AUTUMN_FALL_INTERVAL * (0.5 + Math.random());
      shedRandomLeaf(tree, /* remove = */ true);
    }
    return;
  }

  // Cherry: mostly single petals, with the rare whole blossom. Neither removes
  // anything from the tree (the blossoms stay full), so this rains forever.
  _flowerTimer -= dt;
  if (_flowerTimer <= 0) {
    _flowerTimer = CHERRY_FLOWER_INTERVAL * (0.5 + Math.random());
    shedRandomLeaf(tree, /* remove = */ false);
  }
  _petalTimer -= dt;
  if (_petalTimer <= 0) {
    _petalTimer = CHERRY_PETAL_INTERVAL * (0.5 + Math.random());
    shedCherryPetal(tree);
  }
}

// A single sakura petal: one lobe of the five-petal blossom outline (the same
// radiusFn, sliced to one petal's angular sector) fanned from the flower centre,
// with the blossom's rose→white centre gradient baked into vertex colors. Built
// once at unit size and shared; each falling petal scales/clones to taste.
let _cherryPetalGeo = null;
let _cherryPetalMat = null;
function cherryPetalGeometry() {
  if (_cherryPetalGeo) return _cherryPetalGeo;
  const radiusFn = (a) => 0.6 + 0.4 * Math.cos(5 * a) - 0.12 * Math.cos(10 * a);
  const a0 = -Math.PI / 5, a1 = Math.PI / 5; // one petal, centred on a = 0 (+X)
  const SEG = 24;
  const positions = [];
  const colors = [];
  const rose = new THREE.Color(0xE0559A);
  const white = new THREE.Color(0xffffff);
  const tmp = new THREE.Color();
  const push = (x, y) => {
    positions.push(x, y, 0);
    const c = tmp.copy(rose).lerp(white, Math.min(Math.hypot(x, y) / 0.9, 1));
    colors.push(c.r, c.g, c.b);
  };
  for (let i = 0; i < SEG; i++) {
    const aA = a0 + (a1 - a0) * (i / SEG);
    const aB = a0 + (a1 - a0) * ((i + 1) / SEG);
    const rA = radiusFn(aA), rB = radiusFn(aB);
    push(0, 0);
    push(Math.cos(aA) * rA, Math.sin(aA) * rA);
    push(Math.cos(aB) * rB, Math.sin(aB) * rB);
  }
  const g = new THREE.BufferGeometry();
  g.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  g.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  g.computeVertexNormals();
  _cherryPetalGeo = g;
  return g;
}
function cherryPetalMaterial() {
  if (!_cherryPetalMat) {
    _cherryPetalMat = new THREE.MeshStandardMaterial({
      vertexColors: true, roughness: 0.7, metalness: 0.1,
      side: THREE.DoubleSide, transparent: true, opacity: 0.95
    });
  }
  return _cherryPetalMat;
}

// Launch a single petal from a random blossom on the tree and let it tumble to
// the ground. Nothing is removed from the tree — the petal is a fresh little mesh
// spawned at a blossom's world position, then gsap drifts/tumbles/fades it.
function shedCherryPetal(tree) {
  const meshes = [];
  tree.mesh.traverse(o => { if (o.userData.isLeaf && o.isInstancedMesh && o.count > 0) meshes.push(o); });
  if (!meshes.length) return;
  const src = meshes[Math.floor(Math.random() * meshes.length)];
  const m = new THREE.Matrix4();
  src.getMatrixAt(Math.floor(Math.random() * src.count), m);
  const pos = new THREE.Vector3().setFromMatrixPosition(m.premultiply(src.matrixWorld));

  // Match the petal to the flower's actual size (R = base * 0.8 in the blossom).
  const R = 2.25 * (parameters.foliageSize / 15) * 0.8;
  const petal = new THREE.Mesh(cherryPetalGeometry(), cherryPetalMaterial().clone());
  petal.scale.setScalar(R * (0.8 + Math.random() * 0.4));
  petal.position.copy(pos);
  petal.rotation.set(Math.random() * 6.28, Math.random() * 6.28, Math.random() * 6.28);
  petal.castShadow = true;
  petal.raycast = () => {}; // never intercept prune/shape picks on its way down

  let root = tree.mesh;
  while (root.parent) root = root.parent;
  root.add(petal);

  const dur = 4 + Math.random() * 2;
  gsap.to(petal.position, { y: '-=80', duration: dur, ease: 'power1.in' });
  gsap.to(petal.position, {
    x: `+=${(Math.random() - 0.5) * 40}`,
    z: `+=${(Math.random() - 0.5) * 40}`,
    duration: dur, ease: 'sine.inOut'
  });
  gsap.to(petal.rotation, {
    x: `+=${(Math.random() - 0.5) * 12}`,
    y: `+=${(Math.random() - 0.5) * 12}`,
    z: `+=${(Math.random() - 0.5) * 12}`,
    duration: dur, ease: 'none'
  });
  gsap.to(petal.material, {
    opacity: 0, duration: dur * 0.35, delay: dur * 0.65, ease: 'power1.in',
    onComplete: () => { root.remove(petal); petal.material.dispose(); }
  });
}

// Detach one random leaf/petal and let it flutter down: a falling copy that
// shares the branch's leaf geometry keeps the exact shape, gradient and
// per-instance colors. We re-center the kept instance onto the copy's origin so
// it tumbles about itself, reparent to the scene root so "down" is world-down,
// then gsap drifts it down with a sideways sway, a slow tumble, and a fade. When
// `remove` is set the source instance is collapsed (autumn leaves drop off);
// otherwise it stays on the branch and only a copy falls (whole cherry blossoms
// drift down without thinning the tree — see also shedCherryPetal).
function shedRandomLeaf(tree, remove) {
  const meshes = [];
  tree.mesh.traverse(o => { if (o.userData.isLeaf && o.isInstancedMesh && o.count > 0) meshes.push(o); });
  if (!meshes.length) return;

  // Pick a live (not-yet-shed) instance, retrying since some may be collapsed.
  const m = new THREE.Matrix4();
  const pos = new THREE.Vector3(), quat = new THREE.Quaternion(), scl = new THREE.Vector3();
  let live = null, idx = -1;
  for (let attempt = 0; attempt < 8; attempt++) {
    const cand = meshes[Math.floor(Math.random() * meshes.length)];
    const i = Math.floor(Math.random() * cand.count);
    cand.getMatrixAt(i, m);
    m.decompose(pos, quat, scl);
    if (scl.x > 1e-3) { live = cand; idx = i; break; }
  }
  if (!live) return;

  // Falling copy: same count/geometry so the chosen instance keeps its colors and
  // gradient; every other instance is collapsed so only this one leaf is visible.
  const fall = new THREE.InstancedMesh(live.geometry, live.material.clone(), live.count);
  fall.material.onBeforeCompile = live.material.onBeforeCompile;
  fall.material.needsUpdate = true;
  fall.material.transparent = true;
  fall.castShadow = true;
  const collapsed = new THREE.Matrix4().makeScale(0, 0, 0);
  // Strip the kept instance's translation so the leaf sits on the copy's origin
  // (and thus tumbles about itself); that translation moves onto the mesh below.
  const centered = new THREE.Matrix4().compose(new THREE.Vector3(0, 0, 0), quat, scl);
  for (let i = 0; i < live.count; i++) fall.setMatrixAt(i, i === idx ? centered : collapsed);
  fall.instanceMatrix.needsUpdate = true;

  // Autumn: remove the leaf from the living branch. Cherry: leave it — only the
  // falling copy departs, so the tree never goes bare.
  if (remove) {
    live.setMatrixAt(idx, collapsed);
    live.instanceMatrix.needsUpdate = true;
  }

  // Place the copy at the leaf's spot in the branch frame, then reparent to the
  // scene root (preserving world transform) so it falls straight down.
  fall.position.copy(pos);
  live.parent.add(fall);
  let root = fall;
  while (root.parent) root = root.parent;
  root.attach(fall);

  // Flutter to the ground: a long drift down, a gentle side-to-side sway, a slow
  // tumble, and a fade over the back half of the fall.
  const dur = 3.5 + Math.random() * 1.5;
  gsap.to(fall.position, { y: '-=70', duration: dur, ease: 'power1.in' });
  gsap.to(fall.position, {
    x: `+=${(Math.random() - 0.5) * 30}`,
    z: `+=${(Math.random() - 0.5) * 30}`,
    duration: dur, ease: 'sine.inOut'
  });
  gsap.to(fall.rotation, {
    x: fall.rotation.x + (Math.random() - 0.5) * 6,
    z: fall.rotation.z + (Math.random() - 0.5) * 6,
    duration: dur, ease: 'none'
  });
  gsap.to(fall.material, {
    opacity: 0, duration: dur * 0.4, delay: dur * 0.6, ease: 'power1.in',
    onComplete: () => { root.remove(fall); fall.material.dispose(); }
  });
}

// Mutate a foliage material so it (a) tints each instance by its instanceColor
// and (b) sways in the wind. Shared by needles, leaves, and the falling-offcut
// copies made during a prune. Stores the compiled shader on
// material.userData.shader (handy for debugging) but the sway itself runs off
// the shared windUniforms, so nothing per-frame needs to touch the material.
function injectFoliageShader(material) {
  material.onBeforeCompile = (shader) => {
    shader.uniforms.uTime = windUniforms.uTime;
    shader.uniforms.uWindAmp = windUniforms.uWindAmp;
    shader.uniforms.uWindDir = windUniforms.uWindDir;

    shader.vertexShader = shader.vertexShader
      .replace('#include <common>', `
        #include <common>
        attribute vec3 instanceColor;
        varying vec3 vInstanceColor;
        // Optional within-leaf gradient: a second per-instance color plus a
        // per-vertex ramp (0 at the petiole base → 1 at the tips). Absent on
        // needles and flat-colored leaves, where aGrad defaults to 0 so the
        // fragment mix collapses back to vInstanceColor.
        attribute vec3 instanceColor2;
        varying vec3 vInstanceColor2;
        attribute float aGrad;
        varying float vGrad;
        uniform float uTime;
        uniform float uWindAmp;
        uniform vec2 uWindDir;
      `)
      .replace('#include <begin_vertex>', `
        #include <begin_vertex>
        vInstanceColor = instanceColor;
        vInstanceColor2 = instanceColor2;
        vGrad = aGrad;

        // Instance + model transform (instanceMatrix only exists when instanced).
        mat4 _mi = mat4(1.0);
        #ifdef USE_INSTANCING
          _mi = instanceMatrix;
        #endif
        mat4 _world = modelMatrix * _mi;
        vec3 _wpos = (_world * vec4(0.0, 0.0, 0.0, 1.0)).xyz;

        // Stable per-instance randomness from the world position, so each leaf
        // keeps the same "personality" frame to frame.
        float _hash = fract(sin(dot(_wpos, vec3(12.9898, 78.233, 37.719))) * 43758.5453);
        float _rogue = step(0.85, _hash); // ~15% of foliage marches to its own beat

        // Coherent gust: phase comes from the instance's WORLD position projected
        // along the wind direction, minus time — a wave that travels downwind so
        // neighbours sway together and the gust sweeps across the tree. A small
        // universal jitter plus a big offset on the rogue minority break the
        // robotic unison.
        float _phase = dot(_wpos.xz, uWindDir) * 0.04 - uTime * 1.3
                     + _hash * 0.6
                     + _rogue * _hash * 5.0;
        float _gust = sin(_phase) + 0.3 * sin(_phase * 2.3 + 1.7);

        // Breathing envelope: a slow swell/lull that drifts across space, so the
        // wind comes in gusts with calmer spells between them instead of a steady
        // wobble. The pow() keeps it low (calm) most of the time with brief peaks.
        float _env = 0.25 + 0.75 * pow(0.5 + 0.5 * sin(uTime * 0.4 + _wpos.x * 0.02), 2.0);

        // Rogue foliage keeps a faint flutter through the lulls, so a few things
        // are always moving even when the canopy is calm.
        float _idle = _rogue * 0.3 * sin(uTime * 2.0 + _hash * 6.2831);

        float _sway = _gust * _env + _idle;

        // Foliage is modelled with its attachment at local y=0 and the free end up
        // +y, so scale by height above the anchor: the base stays pinned and only
        // the tip flutters (a bend, not a drift).
        float _h = max(transformed.y, 0.0);

        // Push everything the SAME way in world space (along the wind), then bring
        // that offset back into local space so it survives the transform that
        // follows. Uniform instance scale assumed: M^-1 = M^T / scale^2.
        vec3 _worldOffset = vec3(uWindDir.x, 0.1, uWindDir.y) * (_sway * uWindAmp * _h);
        mat3 _m = mat3(_world);
        transformed += (_worldOffset * _m) / max(dot(_m[0], _m[0]), 1e-4);
      `);

    shader.fragmentShader = shader.fragmentShader
      .replace('#include <common>', `
        #include <common>
        varying vec3 vInstanceColor;
        varying vec3 vInstanceColor2;
        varying float vGrad;
      `)
      .replace('#include <dithering_fragment>', `
        #include <dithering_fragment>
        // Blend the leaf's base color into its tip color along the ramp (vGrad).
        // vGrad is 0 wherever no ramp was supplied, collapsing this to a flat tint.
        gl_FragColor.rgb *= mix(vInstanceColor, vInstanceColor2, clamp(vGrad, 0.0, 1.0));
      `);

    material.userData.shader = shader;
  };
}

// --- Leaf shapes -----------------------------------------------------------
// All broad-leaf types (everything except pine needles) share the instanced-leaf
// pipeline; they differ only in the blade geometry and, for cherry, the default
// colour. The pinnate types (a single blade with a serrate margin) are driven by
// this table; maple and cherry build radial geometry of their own.
//   length/width  – blade proportions (× the base size)
//   teeth         – marginal tooth count
//   skew          – tooth-apex bias toward the tip (0.5 = symmetric, higher = raked)
//   toothOut/In   – how far teeth project / notches cut
//   crease        – central midrib fold depth
const LEAF_SHAPES = {
  deciduous: { length: 1.0, width: 1.0,  teeth: 6,  skew: 0.7,  toothOut: 0.18, notchIn: 0.10, crease: 0.08 },
  willow:    { length: 1.9, width: 0.34, teeth: 13, skew: 0.85, toothOut: 0.10, notchIn: 0.05, crease: 0.05 },
};

// Which colour palette a leaf type draws from. Cherry defaults to the soft
// blossom pinks, but an explicit (non-default) foliageColor choice still wins.
function leafPalette() {
  if (parameters.leafType === 'cherry' && parameters.foliageColor === 'greens') return 'blossom';
  return parameters.foliageColor;
}

// Needled (conifer) leaf types: built as instanced needles rather than broad
// leaves, share the updateNeedleColors / prune-drop paths, and never shed.
// 'pine' is the original short tufted needle; 'candle' is the upswept long-needle
// candle. Add new conifers here so every needle/leaf branch routes them together.
function isNeedleType(t = parameters.leafType) {
  return t === 'pine' || t === 'candle';
}

// Palettes that look best with a within-leaf gradient rather than one flat tint.
// Autumn foliage turns unevenly — margins/tips redden while the heart stays gold —
// so each leaf blends two of the palette's colors from base to tip.
function paletteIsGradient(palette) {
  return palette === 'autumn';
}

// Pick the color(s) for one leaf instance and return [baseColor, tipColor]. For a
// flat palette tip === base (a no-op gradient). The draw order is identical to the
// old single-color path for flat palettes, so seeded replay of non-autumn trees is
// unchanged; gradient palettes draw a second color on top. For a gradient, the
// redder of the two colors is forced to the tip, since fall leaves redden from the
// margins inward.
function pickLeafColors(palette, gradient) {
  const jitter = (c) => c.offsetHSL(
    (Math2.random() - 0.5) * 0.08,
    (Math2.random() - 0.5) * 0.15,
    (Math2.random() - 0.5) * 0.2
  );
  const base = jitter(new THREE.Color(Colors.getRandomFrom(palette)));
  if (!gradient) return [base, base];
  const tip = jitter(new THREE.Color(Colors.getRandomFrom(palette)));
  const redness = (c) => c.r - 0.5 * (c.g + c.b);
  return redness(tip) >= redness(base) ? [base, tip] : [tip, base];
}

// Add an `aGrad` attribute (one float per vertex, 0→1) used by the foliage shader
// to blend a leaf's base color into its tip color. The ramp is the vertex's
// distance from the petiole base (the local origin) normalised by the farthest
// vertex, so it runs base→tip on every leaf shape with no per-shape code. Works on
// the merged stem+blade geometry: the petiole near the origin stays at the base
// color and the blade extremities reach the tip color.
function addLeafGradientRamp(geom) {
  const pos = geom.attributes.position;
  const n = pos.count;
  const grad = new Float32Array(n);
  let max = 0;
  for (let i = 0; i < n; i++) {
    const d = Math.hypot(pos.getX(i), pos.getY(i), pos.getZ(i));
    grad[i] = d;
    if (d > max) max = d;
  }
  if (max > 0) for (let i = 0; i < n; i++) grad[i] /= max;
  geom.setAttribute('aGrad', new THREE.BufferAttribute(grad, 1));
}

// Paper-birch bark texture. The lathe trunk/main-branch geometry clusters its
// vertex rings toward the top, so per-vertex banding can't draw streaks on the
// wide lower trunk — a texture sampled per fragment can, using the UVs LatheGeometry
// already provides (u around the trunk, v up it). Drawn once, cached, and reused;
// uses Math.random (cosmetic, like environment.js) so it never touches the seeded
// geometry stream. Multiplies against the near-white birch vertex colors, so the
// dark lenticel dashes read through while the bark keeps its shaded variation.
let _birchTexture = null;
function getBirchTexture() {
  if (_birchTexture) return _birchTexture;
  const w = 256, h = 1024;
  const canvas = document.createElement('canvas');
  canvas.width = w;
  canvas.height = h;
  const ctx = canvas.getContext('2d');

  // Off-white base with a faint warm tint (matches BIRCH_BARK).
  ctx.fillStyle = '#efeadf';
  ctx.fillRect(0, 0, w, h);

  // Sparse faint grey vertical smudges for a papery feel.
  ctx.globalAlpha = 0.05;
  ctx.fillStyle = '#9a948a';
  for (let i = 0; i < 24; i++) {
    const x = Math.random() * w;
    ctx.fillRect(x, 0, 1 + Math.random() * 2, h);
  }
  ctx.globalAlpha = 1;

  // Horizontal lenticel bands: rows of short dark dashes, irregularly spaced up
  // the height, each broken into dashes around the circumference (x). Wrapping
  // dashes across the x seam keeps the bands continuous around the trunk.
  const bands = 22;
  for (let b = 0; b < bands; b++) {
    const y = (b + 0.5) / bands * h + (Math.random() - 0.5) * (h / bands) * 0.5;
    const thickness = 2 + Math.random() * 4;
    const darkness = 0.35 + Math.random() * 0.45;
    ctx.fillStyle = `rgba(30,28,26,${darkness})`;
    let x = Math.random() * 40;
    while (x < w) {
      const dashLen = 6 + Math.random() * 34;
      ctx.fillRect(x, y, dashLen, thickness);
      if (x + dashLen > w) ctx.fillRect(x - w, y, dashLen, thickness); // wrap the seam
      x += dashLen + 6 + Math.random() * 26; // gap between dashes
    }
  }

  const tex = new THREE.CanvasTexture(canvas);
  tex.colorSpace = THREE.SRGBColorSpace;
  tex.wrapS = THREE.RepeatWrapping;   // seamless around the trunk
  tex.wrapT = THREE.ClampToEdgeWrapping;
  _birchTexture = tex;
  return tex;
}

// Set or clear the birch bark texture on a bark material to match the current
// trunk color. Called wherever a lathe bark material is built or live-recolored.
function syncBirchTexture(material) {
  if (!material) return;
  const want = parameters.truncColor === BIRCH_BARK ? getBirchTexture() : null;
  if (material.map !== want) {
    material.map = want;
    material.needsUpdate = true;
  }
}

// A re-parameterized slice [t0, t1] of an existing curve, used to rebuild a
// branch tube over just part of its length when a branch is partially pruned.
class SubCurve extends THREE.Curve {
  constructor(base, t0, t1) {
    super();
    this.base = base;
    this.t0 = t0;
    this.t1 = t1;
  }
  getPoint(t, target = new THREE.Vector3()) {
    return this.base.getPoint(this.t0 + (this.t1 - this.t0) * t, target);
  }
}

    class Tree {
      constructor(seed) {
        // Seed the shared RNG BEFORE any geometry is built, so the whole tree
        // (trunk, branches, roots, foliage colors) is reproducible from this seed.
        // A missing seed means a brand-new random tree; we still capture the seed
        // so it can be saved and replayed later.
        this.seed = (seed >>> 0) || ((Math.random() * 0xffffffff) >>> 0);
        Math2.seed(this.seed);

        // Ordered log of post-generation structural edits (grow/prune/shape).
        // Replayed on load to reproduce a tree exactly — see record() and
        // main.js createNewTreeWithData(). Cosmetic actions never go here.
        this.history = [];

        // Monotonic counter for main-branch ids ('m#N'). Monotonic (never reused)
        // so ids stay unique even after a main branch is pruned and another added;
        // it advances identically on replay because the same calls run in order.
        this._mainSeq = 0;

        this.mesh = new THREE.Group();
        this.branches = [];
        this.createTrunk();
      }

      // Append a structural edit to the history log (no-op safety if called
      // before the array exists). Entries are plain JSON so they serialize.
      record(entry) {
        if (this.history) this.history.push(entry);
      }

      updateLeafType() {
  this.branches.forEach(branch => {
    if (branch.updateLeafType) {
      branch.updateLeafType();
    }
  });
}

updateSubBranchFoliage(mainBranchGroup) {
  
  const updateFoliageRecursively = (object) => {
    // Look for Branch objects (they have userData.branch)
    if (object.userData && object.userData.branch) {
      const branch = object.userData.branch;
      if (branch.updateLeafType) {
        branch.updateLeafType();
      }
    }
    
    // Recursively check children
    if (object.children) {
      object.children.forEach(child => updateFoliageRecursively(child));
    }
  };
  
  updateFoliageRecursively(mainBranchGroup);
}

// Method to update foliage colors on sub-branches
updateSubBranchFoliageColors(mainBranchGroup) {
  
  const updateColorsRecursively = (object) => {
    // Look for Branch objects
    if (object.userData && object.userData.branch) {
      const branch = object.userData.branch;
      
      if (isNeedleType() && branch.updateNeedleColors) {
        branch.updateNeedleColors();
      } else if (!isNeedleType() && branch.updateLeafColors) {
        branch.updateLeafColors();
      }
    }

    // Recursively check children
    if (object.children) {
      object.children.forEach(child => updateColorsRecursively(child));
    }
  };
  
  updateColorsRecursively(mainBranchGroup);
}

// Create trunk with low poly aesthetic, proper tapering, and random lean
createTrunk(isRebuild = false) {
  // When rebuilding in place (live trunk edits) drop the previous trunk meshes,
  // disposing their GPU resources so a long slider drag doesn't leak memory.
  if (this._trunkParts) {
    this._trunkParts.forEach(m => {
      this.mesh.remove(m);
      if (m.geometry) m.geometry.dispose();
      if (m.material) m.material.dispose();
    });
  }
  this._trunkParts = [];

  const height = parameters.truncHeight;
  const baseRadius = parameters.truncThickness;

  // The trunk's macro identity (lean + cut-off) is rolled once and reused on
  // every rebuild, so dragging the trunk sliders reshapes the SAME tree rather
  // than spawning a different random one.
  if (!this.trunkShape) {
    this.trunkShape = {
      leanAngle: Math2.rangeRandom(0, Math.PI * 0.25),
      leanDirection: Math2.random() * Math.PI * 2,
      isCutOff: Math2.random() < 0.4,
      // Coherent S-curve identity (option #1). Rolled once so slider drags reshape
      // the SAME gnarl instead of rerolling a new one — same contract as the lean.
      curveAmp: Math2.rangeRandom(0.4, 1.0),     // per-tree intensity, scaled by truncCurve
      curveFreq: Math2.rangeRandom(1.2, 2.6),    // half-waves up the trunk (≈1 → C, ≈2 → S)
      curvePhase: Math2.random() * Math.PI * 2,
      curveDir: Math2.random() * Math.PI * 2,     // horizontal plane the bend sweeps through
    };
  }
  const { leanAngle, leanDirection } = this.trunkShape;
  const leanX = Math.sin(leanDirection) * Math.sin(leanAngle);
  const leanZ = Math.cos(leanDirection) * Math.sin(leanAngle);
  
  // Store these for later use
  this.leanX = leanX;
  this.leanZ = leanZ;
  this.curveStrength = parameters.truncNoise;
  this.height = height;
  this.baseRadius = baseRadius;

  // Smooth lateral wander down the trunk, a pure function of height so every vertex
  // in a height-ring shifts together. Because it's coherent (unlike truncNoise's
  // per-vertex jitter), extractTrunkCenterline() picks it up and branches reattach
  // to the curved trunk for free. The ×t anchor keeps the base planted in the pot.
  const { curveAmp, curveFreq, curvePhase, curveDir } = this.trunkShape;
  const curveDirX = Math.cos(curveDir);
  const curveDirZ = Math.sin(curveDir);
  const trunkBend = (y) => {
    const tt = y / height;
    const mag = parameters.truncCurve * curveAmp *
                Math.sin(tt * curveFreq * Math.PI + curvePhase) * tt;
    return { x: curveDirX * mag, z: curveDirZ * mag };
  };
  
  // Create trunk points
const points = [];
const segments = 14;

points.push(new THREE.Vector2(baseRadius, 0));

const isCutOff = this.trunkShape.isCutOff; // rolled once; stable across rebuilds
const endHeight = isCutOff ? height * 0.8 : height; // Cut short if cut-off

for (let i = 1; i <= segments; i++) {
  // Bias the rings toward the top: t = 1-(1-u)^p with p>1 clusters samples where
  // the taper AND the S-curve change fastest, so a sharp upper bend no longer has
  // to span one long lathe facet (which read as a stretched top segment).
  const u = i / segments;
  const t = 1 - Math.pow(1 - u, 2.7);
  const actualT = isCutOff ? t * 0.8 : t; // Compress the taper if cut-off
  const radiusAtHeight = baseRadius * Math.pow(1 - actualT, 1.5);
  const currentY = height * actualT;

  points.push(new THREE.Vector2(Math.max(radiusAtHeight, 0.8), currentY));
}

// Store if this trunk was cut off so we can add a cap
this.trunkIsCutOff = isCutOff;
this.trunkEndHeight = endHeight;
this.trunkEndRadius = isCutOff ? baseRadius * 0.3 : 0.8;

  // Create geometry
  const trunkGeometry = new THREE.LatheGeometry(points, 6);
  
  // Apply transformations and track final positions
  this.trunkCurveData = [];
  const geometryPositions = trunkGeometry.attributes.position;
  
  // Apply the same transformations as before, but track the results
  for (let i = 0; i < geometryPositions.count; i++) {
    const y = geometryPositions.getY(i);
    const t = y / height;
    
    if (t > 0) {
      // Apply lean
      const leanOffsetX = leanX * y * 0.8;
      const leanOffsetZ = leanZ * y * 0.8;
      
      // Add random displacement
      const noiseX = (Math2.random() - 0.5) * parameters.truncNoise * (1 - t);
      const noiseZ = (Math2.random() - 0.5) * parameters.truncNoise * (1 - t);

      const bend = trunkBend(y);
      const finalX = geometryPositions.getX(i) + leanOffsetX + bend.x + noiseX;
      const finalZ = geometryPositions.getZ(i) + leanOffsetZ + bend.z + noiseZ;

      geometryPositions.setX(i, finalX);
      geometryPositions.setZ(i, finalZ);
    }
  }
  geometryPositions.needsUpdate = true;
  trunkGeometry.computeVertexNormals();
  
  // NOW extract the actual centerline positions from the transformed geometry
  this.extractTrunkCenterline(geometryPositions, points);
  
  // Rest of trunk creation (colors, material, etc.)
  const colors = [];
  const positions = trunkGeometry.attributes.position;
  const baseColor = new THREE.Color(parameters.truncColor);
  
  for (let i = 0; i < positions.count; i++) {
    const y = positions.getY(i);
    const heightRatio = y / height;
    
    const color = baseColor.clone();
    color.offsetHSL(0, 0, heightRatio * 0.2 - 0.1);
    color.offsetHSL((Math2.random() - 0.5) * 0.05, 0, (Math2.random() - 0.5) * 0.1);

    colors.push(color.r, color.g, color.b);
  }

  trunkGeometry.setAttribute('color', new THREE.BufferAttribute(new Float32Array(colors), 3));
  
  const trunkMaterial = new THREE.MeshStandardMaterial({
    vertexColors: true,
    roughness: 0.8,
    metalness: 0.1,
    flatShading: true
  });
  syncBirchTexture(trunkMaterial);

  const trunkMesh = new THREE.Mesh(trunkGeometry, trunkMaterial);
  trunkMesh.castShadow = true;
  trunkMesh.receiveShadow = true;

// Create interior wood layer
const interiorPoints = points.map(point => {
  // Make interior slightly smaller (85% of original radius)
  return new THREE.Vector2(point.x * 0.85, point.y);
});

const interiorGeometry = new THREE.LatheGeometry(interiorPoints, 6);

// ROTATE FIRST, before applying transformations
const rotationAngle = Math.PI * 0.3; // Adjust this value as needed
const interiorPositions = interiorGeometry.attributes.position;

// Apply rotation around Y-axis to the base geometry
for (let i = 0; i < interiorPositions.count; i++) {
  const x = interiorPositions.getX(i);
  const z = interiorPositions.getZ(i);
  
  // Rotate around Y-axis
  const newX = x * Math.cos(rotationAngle) - z * Math.sin(rotationAngle);
  const newZ = x * Math.sin(rotationAngle) + z * Math.cos(rotationAngle);
  
  interiorPositions.setX(i, newX);
  interiorPositions.setZ(i, newZ);
}

// NOW apply the same lean and noise transformations as the outer trunk
for (let i = 0; i < interiorPositions.count; i++) {
  const y = interiorPositions.getY(i);
  const t = y / height;
  
  if (t > 0) {
    const leanOffsetX = leanX * y * 0.8;
    const leanOffsetZ = leanZ * y * 0.8;
    const noiseX = (Math2.random() - 0.5) * parameters.truncNoise * (1 - t);
    const noiseZ = (Math2.random() - 0.5) * parameters.truncNoise * (1 - t);
    
    const bend = trunkBend(y);
    const finalX = interiorPositions.getX(i) + leanOffsetX + bend.x + noiseX;
    const finalZ = interiorPositions.getZ(i) + leanOffsetZ + bend.z + noiseZ;

    interiorPositions.setX(i, finalX);
    interiorPositions.setZ(i, finalZ);
  }
}
interiorPositions.needsUpdate = true;
interiorGeometry.computeVertexNormals();

// Create lighter wood colors for interior
const interiorColors = [];
const interiorPos = interiorGeometry.attributes.position;
const interiorBaseColor = new THREE.Color(parameters.truncColor);
interiorBaseColor.offsetHSL(0, -0.2, 0.3); // Lighter, less saturated

for (let i = 0; i < interiorPos.count; i++) {
  const y = interiorPos.getY(i);
  const heightRatio = y / height;
  
  const color = interiorBaseColor.clone();
  color.offsetHSL(0, 0, heightRatio * 0.15 - 0.05);
  color.offsetHSL((Math2.random() - 0.5) * 0.03, 0, (Math2.random() - 0.5) * 0.08);
  
  interiorColors.push(color.r, color.g, color.b);
}

interiorGeometry.setAttribute('color', new THREE.BufferAttribute(new Float32Array(interiorColors), 3));

const interiorMaterial = new THREE.MeshStandardMaterial({
  vertexColors: true,
  roughness: 0.7,
  metalness: 0.1,
  flatShading: true,
  side: THREE.BackSide // Important: render from inside
});

const interiorMesh = new THREE.Mesh(interiorGeometry, interiorMaterial);
interiorMesh.castShadow = false; // Don't cast shadows
interiorMesh.receiveShadow = true;
interiorMesh.raycast = () => {}; // decorative sap-wood: never intercept prune/shape picks (let the ray reach the bark)

// interior mesh 2
// Create a second interior layer with even lighter wood and different rotation
const interior2Points = points.map(point => {
  // Make this one even smaller (75% of original radius)
  return new THREE.Vector2(point.x * 0.75, point.y);
});

const interior2Geometry = new THREE.LatheGeometry(interior2Points, 6);

// Different rotation angle for better gap coverage
const rotation2Angle = Math.PI * 0.4; // Different angle from first interior
const interior2Positions = interior2Geometry.attributes.position;

// Apply rotation around Y-axis to the base geometry
for (let i = 0; i < interior2Positions.count; i++) {
  const x = interior2Positions.getX(i);
  const z = interior2Positions.getZ(i);
  
  // Rotate around Y-axis with different angle
  const newX = x * Math.cos(rotation2Angle) - z * Math.sin(rotation2Angle);
  const newZ = x * Math.sin(rotation2Angle) + z * Math.cos(rotation2Angle);
  
  interior2Positions.setX(i, newX);
  interior2Positions.setZ(i, newZ);
}

// Apply the same lean and noise transformations
for (let i = 0; i < interior2Positions.count; i++) {
  const y = interior2Positions.getY(i);
  const t = y / height;
  
  if (t > 0) {
    const leanOffsetX = leanX * y * 0.8;
    const leanOffsetZ = leanZ * y * 0.8;
    const noiseX = (Math2.random() - 0.5) * parameters.truncNoise * (1 - t);
    const noiseZ = (Math2.random() - 0.5) * parameters.truncNoise * (1 - t);
    
    const bend = trunkBend(y);
    const finalX = interior2Positions.getX(i) + leanOffsetX + bend.x + noiseX;
    const finalZ = interior2Positions.getZ(i) + leanOffsetZ + bend.z + noiseZ;

    interior2Positions.setX(i, finalX);
    interior2Positions.setZ(i, finalZ);
  }
}
interior2Positions.needsUpdate = true;
interior2Geometry.computeVertexNormals();

// Create even lighter wood colors for second interior
const interior2Colors = [];
const interior2Pos = interior2Geometry.attributes.position;
const interior2BaseColor = new THREE.Color(parameters.truncColor);
interior2BaseColor.offsetHSL(0, -0.1, 0.2); // Even lighter and less saturated

for (let i = 0; i < interior2Pos.count; i++) {
  const y = interior2Pos.getY(i);
  const heightRatio = y / height;
  
  const color = interior2BaseColor.clone();
  color.offsetHSL(0, 0, heightRatio * 0.1 - 0.05);
  color.offsetHSL((Math2.random() - 0.5) * 0.02, 0, (Math2.random() - 0.5) * 0.06);
  
  interior2Colors.push(color.r, color.g, color.b);
}

interior2Geometry.setAttribute('color', new THREE.BufferAttribute(new Float32Array(interior2Colors), 3));

const interior2Material = new THREE.MeshStandardMaterial({
  vertexColors: true,
  roughness: 0.6,
  metalness: 0.1,
  flatShading: true
  // Normal rendering (both sides) - no BackSide
});

const interior2Mesh = new THREE.Mesh(interior2Geometry, interior2Material);
interior2Mesh.castShadow = false;
interior2Mesh.receiveShadow = true;
interior2Mesh.raycast = () => {}; // decorative sap-wood: never intercept prune/shape picks (let the ray reach the bark)

// Add both interior layers to this.mesh
this.mesh.add(interior2Mesh);
this.mesh.add(interiorMesh);
  this.mesh.add(trunkMesh);
  this.trunkMesh = trunkMesh;
  this._trunkParts = [interior2Mesh, interiorMesh, trunkMesh];

  // Surface roots (nebari): small tapered sections flaring off the trunk base.
  // Built last so they rebuild alongside the trunk and track its thickness/color.
  // Lives in roots.js; operates on this Tree (reads baseRadius/lean/trunkShape,
  // appends to mesh/_trunkParts).
  createRoots(this);

  // First build only: grow the branches. On a live rebuild they are re-attached
  // to the reshaped trunk instead (see updateTrunkGeometry).
  if (!isRebuild) {
    this.createBranches();
    this.createMainBranches();
  }
}

// Rebuild the trunk geometry in place from the current parameters (height /
// thickness / curvature) and re-attach the existing branches, so the trunk
// sliders reshape the tree live without discarding grown/pruned branches.
updateTrunkGeometry() {
  this.createTrunk(true);

  // Regular branches: re-attach to the new trunk surface. This only moves their
  // base — geometry, foliage and any user shaping (rotation) are preserved.
  const endHeight = this.trunkEndHeight || parameters.truncHeight;
  this.branches.forEach(branch => {
    if (branch.isPruned || branch.heightRatio == null || !branch.reattach) return;
    branch.reattach(this.getTrunkPositionAtHeight(endHeight * branch.heightRatio));
  });

  // Main-branch groups: reposition the group base (their sub-branches ride along
  // in the group's local space).
  this.mesh.children.forEach(child => {
    const ud = child.userData;
    if (!ud || !ud.isMainBranch || ud.heightRatio == null || ud.angle == null) return;
    const trunkPos = this.getTrunkPositionAtHeight(this.height * ud.heightRatio);
    const connectionDepth = trunkPos.radius * 0.2;
    child.position.set(
      trunkPos.x + Math.cos(ud.angle) * connectionDepth,
      trunkPos.y,
      trunkPos.z + Math.sin(ud.angle) * connectionDepth
    );
  });

  // Re-bend (Curve) and re-crinkle (Roughness) the main branches and re-place their
  // sub-branches onto the new centerline — the same way createTrunk(true) re-noises
  // the trunk and reattaches its branches on every reshape.
  this.updateMainBranchShape();

  // Thin the main branches if the trunk got thinner, so none ends up fatter than
  // the trunk it sprouts from.
  this.updateMainBranchThickness();
}

// Keep each main branch's girth proportional to the trunk: as the trunk thickness
// slider shrinks the trunk, scale the branch's lathe meshes radially (X/Z only,
// leaving length and the parented sub-branches/foliage alone) by how much thinner
// the trunk now is than when the branch was built. Clamped at 1 — a thicker trunk
// doesn't fatten the branches back up (thinner-than-trunk reads fine; fatter
// looks silly). Idempotent: the scale is absolute, recomputed from the as-built
// radius each call, so dragging the slider back and forth doesn't compound.
updateMainBranchThickness() {
  this.mesh.children.forEach(group => {
    const built = group.userData && group.userData.isMainBranch && group.userData.buildBaseRadius;
    if (!built) return;
    const scale = Math.min(1, this.baseRadius / built);
    group.children.forEach(mesh => {
      const ud = mesh.userData;
      // The end caps live in the same group-local frame as the lathe (geometry on
      // the branch axis, identity mesh transform), so scaling x/z shrinks them in
      // lockstep — otherwise a thinned branch flares back out at the cap.
      if (ud && (ud.isMainBranch || ud.isMainBranchInterior || ud.isBrokenCap || ud.isEndCap)) {
        mesh.scale.x = scale;
        mesh.scale.z = scale;
      }
    });
  });
}

// Re-derive every main branch's geometry from the live parameters, the same way
// createTrunk(true) rebuilds the trunk on a slider drag. Each lathe mesh is rebuilt
// from its stored pre-noise base with the current lean + Curve bend (truncCurve) +
// Roughness (truncNoise) re-applied, so the Curve slider bends the main branches and
// the Roughness slider re-crinkles them. Because the bend can shift the branch a lot,
// the centerline is re-extracted and the sub-branches (and end cap) are re-placed onto
// it — so branches stay attached to the main branch through the curve, just like trunk
// branches reattach when the trunk is reshaped.
updateMainBranchShape() {
  this.mesh.children.forEach(group => {
    const gud = group.userData;
    if (!gud || !gud.isMainBranch) return;

    // Rebuild the lathe meshes (outer + interior layers) with lean + curve + noise.
    let outerMesh = null;
    group.children.forEach(mesh => {
      const ud = mesh.userData;
      if (ud && ud.noiseBase) {
        this._applyMainBranchNoise(mesh.geometry, ud.noiseBase, ud.leanX, ud.leanZ,
          ud.branchLength, gud.curveShape, gud.curveScale);
        if (ud.isMainBranch) outerMesh = mesh;
      }
    });
    if (!outerMesh || gud.buildLength == null) return;

    // Re-extract the bent centerline so attachments follow the new curve.
    const oldCenterline = gud.centerline;
    let newCenterline = this.extractMainBranchCenterline(
      outerMesh.geometry.attributes.position,
      [{ x: gud.buildThickness }],
      gud.buildLength
    );
    // The lathe positions still hold the rings past a prune (only their faces were
    // dropped), so clip the re-extracted centerline back to the surviving length —
    // otherwise sub-branches would reattach to the lopped-off, invisible tip.
    if (gud.cutRing != null && gud.cutRing + 1 < newCenterline.length) {
      newCenterline = newCenterline.slice(0, gud.cutRing + 1);
    }
    gud.centerline = newCenterline;

    // Re-place each sub-branch base onto the bent centerline at its stored height.
    // Same contract as Branch.reattach on the trunk: only the base moves; rotation,
    // geometry, foliage and any user shaping are preserved.
    group.children.forEach(child => {
      const sub = child.userData && child.userData.branch;
      if (!sub || sub.isPruned || sub.parentHeight == null || !sub.reattach) return;
      sub.reattach(this.getMainBranchPositionAtHeight(newCenterline, sub.parentHeight));
    });

    // Slide the end cap along by however far the tip moved, so it stays on the tip
    // without re-jittering the broken-cap geometry (which would "boil" every drag).
    if (oldCenterline && oldCenterline.length && newCenterline.length) {
      const oTip = oldCenterline[oldCenterline.length - 1];
      const nTip = newCenterline[newCenterline.length - 1];
      const dx = nTip.x - oTip.x, dy = nTip.y - oTip.y, dz = nTip.z - oTip.z;
      group.children.forEach(child => {
        const ud = child.userData;
        if (ud && (ud.isEndCap || ud.isBrokenCap)) {
          child.position.x += dx; child.position.y += dy; child.position.z += dz;
        }
      });
    }
  });
}

updateTrunkColor() {
    
    if (!this.trunkMesh) {
      return;
    }

    const newColor = new THREE.Color(parameters.truncColor);
    
    // Update trunk colors
    if (this.trunkMesh.geometry.attributes.color) {
      const colors = this.trunkMesh.geometry.attributes.color.array;
      const positions = this.trunkMesh.geometry.attributes.position;
      const height = this.height;
      
      for (let i = 0; i < positions.count; i++) {
        const y = positions.getY(i);
        const heightRatio = y / height;
        
        const color = newColor.clone();
        color.offsetHSL(0, 0, heightRatio * 0.2 - 0.1);
        color.offsetHSL((Math2.random() - 0.5) * 0.05, 0, (Math2.random() - 0.5) * 0.1);

        const colorIndex = i * 3;
        colors[colorIndex] = color.r;
        colors[colorIndex + 1] = color.g;
        colors[colorIndex + 2] = color.b;
      }

      this.trunkMesh.geometry.attributes.color.needsUpdate = true;
      syncBirchTexture(this.trunkMesh.material);
    }

    // Update interior trunk layers
    this.mesh.children.forEach(child => {
      if (child !== this.trunkMesh && child.material && child.material.vertexColors) {
        if (child.geometry.attributes.color) {
          const colors = child.geometry.attributes.color.array;
          const positions = child.geometry.attributes.position;
          
          const interiorColor = newColor.clone();
          interiorColor.offsetHSL(0, -0.2, 0.3);
          
          for (let i = 0; i < positions.count; i++) {
            const y = positions.getY(i);
            const heightRatio = y / this.height;
            
            const color = interiorColor.clone();
            color.offsetHSL(0, 0, heightRatio * 0.15 - 0.05);
            color.offsetHSL((Math2.random() - 0.5) * 0.03, 0, (Math2.random() - 0.5) * 0.08);
            
            const colorIndex = i * 3;
            colors[colorIndex] = color.r;
            colors[colorIndex + 1] = color.g;
            colors[colorIndex + 2] = color.b;
          }
          
          child.geometry.attributes.color.needsUpdate = true;
        }
      }
    });

    // Update main branches - look for groups marked as main branches
    this.mesh.children.forEach((child, index) => {
      if (child.userData && child.userData.isMainBranch) {
        this.updateMainBranchColors(child, newColor);
      }
    });

    // Update regular branches (the ones in this.branches array)
    if (this.branches) {
      this.branches.forEach((branch, index) => {
        if (branch.branchMesh && branch.branchMesh.geometry.attributes.color) {
          this.updateRegularBranchColors(branch, newColor);
        }
      });
    }

    // End caps are solid-colored meshes (no vertex-color attribute), so the
    // per-branch recolor loops above skip them. They also live at many nesting
    // depths (twigs, main-branch sub-branches, twigs of those). One traverse
    // over the whole tree recolors every cap by its isEndCap flag — can't miss
    // one — using the same offset _makeCap() applies from truncColor.
    this.mesh.traverse(obj => {
      if (obj.userData.isBrokenCap && obj.geometry && obj.geometry.attributes.color) {
        // Repaint the bark→heartwood gradient against the new trunk color.
        this._fillBrokenCapColors(obj.geometry.attributes.color.array, obj.userData.capFracs, newColor);
        obj.geometry.attributes.color.needsUpdate = true;
      } else if (obj.userData.isEndCap && obj.material) {
        obj.material.color.copy(newColor).offsetHSL(0, -0.1, 0.3);
      }
    });
  }

  updateSubBranchColors(subBranchGroup, newTrunkColor) {
  
  subBranchGroup.children.forEach((child, childIndex) => {

    // Look for the branch mesh (usually a mesh with tube geometry)
    if (child.type === 'Mesh' && child.material && child.geometry.attributes.color) {
      
      const colors = child.geometry.attributes.color.array;
      const positions = child.geometry.attributes.position;
      
      // For sub-branches, find max Z (they extend along Z axis like regular branches)
      let maxZ = -Infinity;
      for (let i = 0; i < positions.count; i++) {
        const z = positions.getZ(i);
        if (z > maxZ) maxZ = z;
      }
      
      for (let i = 0; i < positions.count; i++) {
        const z = positions.getZ(i);
        const lengthRatio = maxZ > 0 ? z / maxZ : 0;
        
        const color = newTrunkColor.clone();
        color.offsetHSL(0, 0, lengthRatio * 0.15);
        color.offsetHSL((Math2.random() - 0.5) * 0.05, 0, (Math2.random() - 0.5) * 0.1);
        applyBirchBand(color, positions, i, lengthRatio, 'z');

        const colorIndex = i * 3;
        colors[colorIndex] = color.r;
        colors[colorIndex + 1] = color.g;
        colors[colorIndex + 2] = color.b;
      }
      
      child.geometry.attributes.color.needsUpdate = true;
    }
    
    // Handle foliage groups within sub-branches (if they have needles)
    else if (child.type === 'Group') {
      child.children.forEach((grandchild, grandchildIndex) => {
        if (grandchild.type === 'Mesh' && grandchild.material && grandchild.geometry.attributes.color) {
          
          const colors = grandchild.geometry.attributes.color.array;
          const positions = grandchild.geometry.attributes.position;
          
          // Same logic as above for nested meshes
          let maxZ = -Infinity;
          for (let i = 0; i < positions.count; i++) {
            const z = positions.getZ(i);
            if (z > maxZ) maxZ = z;
          }
          
          for (let i = 0; i < positions.count; i++) {
            const z = positions.getZ(i);
            const lengthRatio = maxZ > 0 ? z / maxZ : 0;
            
            const color = newTrunkColor.clone();
            color.offsetHSL(0, 0, lengthRatio * 0.15);
            color.offsetHSL((Math2.random() - 0.5) * 0.05, 0, (Math2.random() - 0.5) * 0.1);
            applyBirchBand(color, positions, i, lengthRatio, 'z');

            const colorIndex = i * 3;
            colors[colorIndex] = color.r;
            colors[colorIndex + 1] = color.g;
            colors[colorIndex + 2] = color.b;
          }
          
          grandchild.geometry.attributes.color.needsUpdate = true;
        }
      });
    }
  });
}

// Updated createMainBranches function with animation
createMainBranches() {
  const numMainBranches = Math.floor(Math2.random() * 3); // 1-3 branches
  
  for (let i = 0; i < numMainBranches; i++) {
    // Position main branches low on the trunk, where the taper is still thick
    const heightRatio = 0.01 + (Math2.random() * 0.11);
    const branchHeight = this.height * heightRatio;
    
    // Get trunk position at this height
    const trunkPos = this.getTrunkPositionAtHeight(branchHeight);
    
    // Create main branch parameters
    const branchLength = this.height * (0.4 + Math2.random() * 0.3); // 40-70% of trunk height
    const branchThickness = this.baseRadius * (0.5 + Math2.random() * 0.18); // 50-68% of trunk thickness
    const angle = (Math.PI * 2 / numMainBranches) * i + Math2.random() * 0.5;
    
    // Create main branch (monotonic id; loop i still drives the fan-out angle)
    const mainBranch = this.createMainBranch(
      branchLength,
      branchThickness,
      angle,
      trunkPos,
      this._mainSeq++
    );
    
    // Start main branch at zero scale for animation
    mainBranch.scale.set(0.01, 0.01, 0.01);
    
    this.mesh.add(mainBranch);
    
    // Animate main branch growing with staggered timing
    gsap.to(mainBranch.scale, {
      x: 1, y: 1, z: 1,
      duration: 1.2 + Math.random() * 0.8, // cosmetic timing — stays off the seeded stream
      ease: "back.out(1.7)",
      delay: i * 0.3 + Math.random() * 0.2 // cosmetic timing — stays off the seeded stream
    });
  }
}

updateRegularBranchColors(branch, newTrunkColor) {
  const colors = branch.branchMesh.geometry.attributes.color.array;
  const positions = branch.branchMesh.geometry.attributes.position;
  
  // Find max Z (since regular branches extend along Z axis)
  let maxZ = -Infinity;
  for (let i = 0; i < positions.count; i++) {
    const z = positions.getZ(i);
    if (z > maxZ) maxZ = z;
  }
  
  for (let i = 0; i < positions.count; i++) {
    const z = positions.getZ(i);
    const lengthRatio = maxZ > 0 ? z / maxZ : 0;
    
    const color = newTrunkColor.clone();
    color.offsetHSL(0, 0, lengthRatio * 0.15);
    color.offsetHSL((Math2.random() - 0.5) * 0.05, 0, (Math2.random() - 0.5) * 0.1);
    applyBirchBand(color, positions, i, lengthRatio, 'z');

    const colorIndex = i * 3;
    colors[colorIndex] = color.r;
    colors[colorIndex + 1] = color.g;
    colors[colorIndex + 2] = color.b;
  }
  
  branch.branchMesh.geometry.attributes.color.needsUpdate = true;

  // (End caps are recolored in one traverse pass at the end of updateTrunkColor.)

  // Twigs are third-level branches parented to this one but not registered in
  // tree.branches, so recurse here or their bark keeps the old trunk color.
  if (branch.twigs) {
    branch.twigs.forEach(twig => this.updateRegularBranchColors(twig, newTrunkColor));
  }
}

// Restore a main branch's lathe vertices from their pre-noise snapshot, then
// re-apply lean + procedural roughness (scaled by parameters.truncNoise, fading
// toward the tip). Driven from a saved `base` so it can be re-run live when the
// Roughness slider changes, the way the trunk re-noises on reshape.
_applyMainBranchNoise(geometry, base, leanX, leanZ, length, curveShape, curveScale) {
  const positions = geometry.attributes.position;
  const curveStrength = parameters.truncNoise * 0.7;

  // Coherent lateral bend, identical in form to the trunk's trunkBend(): a pure
  // function of position along the branch (t = y/length), scaled by truncCurve so
  // the Curve slider drives it live. Deterministic (no RNG), so it never perturbs
  // the seeded stream replay depends on. curveScale keeps it proportional to the
  // trunk. The ×t anchor pins the base to the trunk so the branch stays attached.
  const bendDirX = curveShape ? Math.cos(curveShape.curveDir) : 0;
  const bendDirZ = curveShape ? Math.sin(curveShape.curveDir) : 0;
  const scale = curveScale || 1;

  for (let i = 0; i < positions.count; i++) {
    const baseX = base[i * 3];
    const y = base[i * 3 + 1];
    const baseZ = base[i * 3 + 2];
    const t = y / length;

    if (t > 0) {
      const leanOffsetX = leanX * y * 0.6;
      const leanOffsetZ = leanZ * y * 0.6;
      const noiseX = (Math2.random() - 0.5) * curveStrength * (1 - t);
      const noiseZ = (Math2.random() - 0.5) * curveStrength * (1 - t);

      let bendX = 0, bendZ = 0;
      if (curveShape) {
        const mag = parameters.truncCurve * curveShape.curveAmp *
                    Math.sin(t * curveShape.curveFreq * Math.PI + curveShape.curvePhase) * t * scale;
        bendX = bendDirX * mag;
        bendZ = bendDirZ * mag;
      }

      positions.setX(i, baseX + leanOffsetX + noiseX + bendX);
      positions.setZ(i, baseZ + leanOffsetZ + noiseZ + bendZ);
    } else {
      positions.setX(i, baseX);
      positions.setZ(i, baseZ);
    }
  }
  positions.needsUpdate = true;
  geometry.computeVertexNormals();
}

createMainBranch(length, thickness, angle, trunkPos, branchIndex) {
  // Keep the base proportional to the trunk it actually sprouts from. The caller
  // sizes thickness off the trunk's (fat) BASE radius, but branches higher up attach
  // where the trunk has already tapered thin — so cap the base to a fraction of the
  // LOCAL trunk radius. Without this, higher branches read as over-flared stumps at
  // their base. Low branches (local radius ≈ base) fall under the cap and are untouched.
  thickness = Math.min(thickness, trunkPos.radius * 0.75);

  const branchGroup = new THREE.Group();
  
  // IMPORTANT: Mark the GROUP for color updates
  branchGroup.userData.isMainBranch = true;
  branchGroup.userData.branchIndex = branchIndex;
  branchGroup.userData.branchId = 'm#' + branchIndex; // stable id for save/replay
  branchGroup.userData.subCount = 0; // running count of sub-branches, for sub ids
  // Kept so the group can be repositioned if the trunk is reshaped live.
  branchGroup.userData.angle = angle;
  branchGroup.userData.heightRatio = this.height > 0 ? trunkPos.y / this.height : 0;
  // Trunk radius this branch was sized against, so updateMainBranchThickness()
  // can keep the branch proportional (and never fatter than) a thinned trunk.
  branchGroup.userData.buildBaseRadius = this.baseRadius;

  // Coherent curve identity, mirroring the trunk's trunkShape S-curve. Rolled once
  // and stored on the group so dragging the Curve (truncCurve) slider reshapes the
  // SAME bend instead of rerolling a new one — exactly the contract the trunk uses.
  // curveScale keeps the branch's curvature proportional to the trunk's (the trunk
  // bends over its full height; a branch bends the same shape over its own length),
  // captured at build so later height-slider drags don't shift it.
  branchGroup.userData.curveShape = {
    curveAmp: Math2.rangeRandom(0.4, 1.0),
    curveFreq: Math2.rangeRandom(1.2, 2.6),
    curvePhase: Math2.random() * Math.PI * 2,
    curveDir: Math2.random() * Math.PI * 2,
  };
  // 0.5 damping keeps main branches gentler than the trunk (they read as too curly
  // at full strength); the length/height term keeps them proportional to the trunk.
  const MAIN_BRANCH_CURVE_DAMPING = 0.5;
  branchGroup.userData.curveScale =
    (this.height > 0 ? length / this.height : 0.5) * MAIN_BRANCH_CURVE_DAMPING;
  branchGroup.userData.buildLength = length;
  branchGroup.userData.buildThickness = thickness;

  // Position at trunk surface
  const connectionDepth = trunkPos.radius * 0.2;
  const x = trunkPos.x + Math.cos(angle) * connectionDepth;
  const z = trunkPos.z + Math.sin(angle) * connectionDepth;
  
  branchGroup.position.set(x, trunkPos.y, z);
  branchGroup.rotation.y = angle;
  branchGroup.rotation.z = -Math.PI * (0.01 + Math2.random() * 0.35); // Slight upward angle
  
  // Create branch points with cut-off option
  const points = [];
  const segments = 6;
  const segmentLength = length / segments;

  points.push(new THREE.Vector2(thickness, 0));

  const isCutOff = Math2.random() < 0.3; // 30% chance of cut-off
  const endLength = isCutOff ? length * 0.7 : length; // Cut short if cut-off

  for (let i = 1; i <= segments; i++) {
    const t = i / segments;
    const actualT = isCutOff ? t * 0.7 : t; // Compress the taper if cut-off
    const radiusAtLength = thickness * Math.pow(1 - actualT, 1.2);
    const currentLength = (segmentLength * i) * (isCutOff ? 0.7 : 1);
    
    points.push(new THREE.Vector2(Math.max(radiusAtLength, 0.8), currentLength));
  }
    
  // Create geometry 
  const branchGeometry = new THREE.LatheGeometry(points, 6);
  
  // Apply curvature and lean similar to trunk
  const branchLeanX = (Math2.random() - 0.5) * 0.3;
  const branchLeanZ = (Math2.random() - 0.5) * 0.3;

  // Snapshot the pre-noise lathe vertices, then displace. Keeping the base lets
  // the Roughness (truncNoise) slider re-crinkle main branches live, the way the
  // trunk already re-noises on reshape — see updateMainBranchShape().
  const branchBase = Float32Array.from(branchGeometry.attributes.position.array);
  this._applyMainBranchNoise(branchGeometry, branchBase, branchLeanX, branchLeanZ, length,
    branchGroup.userData.curveShape, branchGroup.userData.curveScale);
  const geometryPositions = branchGeometry.attributes.position;
  
  // EXTRACT THE TRANSFORMED CENTERLINE - this is crucial for proper sub-branch attachment
  const mainBranchCenterline = this.extractMainBranchCenterline(geometryPositions, points, length);
  branchGroup.userData.centerline = mainBranchCenterline;
  // Lathe layout, kept so a partial prune can truncate the branch by lopping off
  // the profile rings past the cut (see pruneMainBranchAt / _splitLatheIndex).
  // cutRing is the current tip ring (rings 0..cutRing are present); it shrinks as
  // the branch is pruned, so a later prune/curve-drag clips to the new length.
  branchGroup.userData.latheProfileCount = points.length;
  branchGroup.userData.cutRing = points.length - 1;
  
  // Create colors
  const colors = [];
  const positions = branchGeometry.attributes.position;
  const baseColor = new THREE.Color(parameters.truncColor);
  
  for (let i = 0; i < positions.count; i++) {
    const y = positions.getY(i);
    const lengthRatio = y / length;
    
    const color = baseColor.clone();
    color.offsetHSL(0, 0, lengthRatio * 0.2 - 0.1);
    color.offsetHSL((Math2.random() - 0.5) * 0.05, 0, (Math2.random() - 0.5) * 0.1);

    colors.push(color.r, color.g, color.b);
  }

  branchGeometry.setAttribute('color', new THREE.BufferAttribute(new Float32Array(colors), 3));
  
  const branchMaterial = new THREE.MeshStandardMaterial({
    vertexColors: true,
    roughness: 0.8,
    metalness: 0.1,
    flatShading: true,
    side: THREE.DoubleSide
  });
  syncBirchTexture(branchMaterial);

  const branchMesh = new THREE.Mesh(branchGeometry, branchMaterial);
  branchMesh.castShadow = true;
  branchMesh.receiveShadow = true;

  // Roughness re-application data (see _applyMainBranchNoise / updateMainBranchShape).
  branchMesh.userData.noiseBase = branchBase;
  branchMesh.userData.leanX = branchLeanX;
  branchMesh.userData.leanZ = branchLeanZ;
  branchMesh.userData.branchLength = length;

  // Create a second interior layer with even lighter wood and different rotation
  const interior2Points = points.map(point => {
    // Make this one even smaller (75% of original radius)
    return new THREE.Vector2(point.x * 0.75, point.y);
  });

  const interior2Geometry = new THREE.LatheGeometry(interior2Points, 6);

  // Different rotation angle for better gap coverage
  const rotation2Angle = Math.PI * 0.4; // Different angle from first interior
  const interior2Positions = interior2Geometry.attributes.position;

  // Apply rotation around Y-axis to the base geometry
  for (let i = 0; i < interior2Positions.count; i++) {
    const x = interior2Positions.getX(i);
    const z = interior2Positions.getZ(i);
    
    // Rotate around Y-axis with different angle
    const newX = x * Math.cos(rotation2Angle) - z * Math.sin(rotation2Angle);
    const newZ = x * Math.sin(rotation2Angle) + z * Math.cos(rotation2Angle);
    
    interior2Positions.setX(i, newX);
    interior2Positions.setZ(i, newZ);
  }

  // Snapshot the post-rotation vertices, then displace (same live-roughness path
  // as the outer layer, so the interior re-crinkles with the Roughness slider too).
  const interior2Base = Float32Array.from(interior2Positions.array);
  this._applyMainBranchNoise(interior2Geometry, interior2Base, branchLeanX, branchLeanZ, length,
    branchGroup.userData.curveShape, branchGroup.userData.curveScale);

  // Create even lighter wood colors for second interior
  const interior2Colors = [];
  const interior2Pos = interior2Geometry.attributes.position;
  const interior2BaseColor = new THREE.Color(parameters.truncColor);
  interior2BaseColor.offsetHSL(0, -0.1, 0.2); // Even lighter and less saturated

  for (let i = 0; i < interior2Pos.count; i++) {
    const y = interior2Pos.getY(i);
    const lengthRatio = y / length; // Changed from heightRatio to lengthRatio
    
    const color = interior2BaseColor.clone();
    color.offsetHSL(0, 0, lengthRatio * 0.1 - 0.05);
    color.offsetHSL((Math2.random() - 0.5) * 0.02, 0, (Math2.random() - 0.5) * 0.06);
    
    interior2Colors.push(color.r, color.g, color.b);
  }

  interior2Geometry.setAttribute('color', new THREE.BufferAttribute(new Float32Array(interior2Colors), 3));

  const interior2Material = new THREE.MeshStandardMaterial({
    vertexColors: true,
    roughness: 0.6,
    metalness: 0.1,
    flatShading: true
  });

  const interior2Mesh = new THREE.Mesh(interior2Geometry, interior2Material);
  interior2Mesh.castShadow = false;
  interior2Mesh.receiveShadow = true;
  interior2Mesh.raycast = () => {}; // decorative sap-wood: never intercept prune/shape picks (let the ray reach the bark)

  // Roughness re-application data (see _applyMainBranchNoise / updateMainBranchShape).
  interior2Mesh.userData.noiseBase = interior2Base;
  interior2Mesh.userData.leanX = branchLeanX;
  interior2Mesh.userData.leanZ = branchLeanZ;
  interior2Mesh.userData.branchLength = length;

  // IMPORTANT: Mark interior for color updates
  interior2Mesh.userData.isMainBranchInterior = true;

  branchGroup.add(interior2Mesh);
  branchGroup.add(branchMesh);

  // Cap the open end of the lathe. A clean branch gets a flat bark disk; a
  // cut-off branch gets a torn "broken" cap (jagged, recessed, with concentric
  // heartwood rings) so the snapped wood interior shows instead of a hollow tube.
  const endRadius = points[points.length - 1].x;
  const endCap = this.createMainBranchEndCap(mainBranchCenterline, endRadius, isCutOff);
  if (endCap) branchGroup.add(endCap);

  // KEEP YOUR ORIGINAL PRUNING SYSTEM - this is what makes pruning work!
  branchMesh.userData.isMainBranch = true;
  branchMesh.userData.branchGroup = branchGroup;

  // Add sub-branches to this main branch
  this.addBranchesToMainBranch(branchGroup, length, thickness);
  branchMesh.userData.mainBranch = { group: branchGroup, prune: () => this.pruneMainBranch(branchGroup) };
    
  return branchGroup;
}

// Paint a broken cap's vertex colors: a gradient from bark at the rim (frac 1)
// to lighter, slightly warmer heartwood at the recessed center (frac 0), plus a
// touch of per-vertex grain. Kept separate so updateTrunkColor can repaint live.
_fillBrokenCapColors(colorArray, fracs, trunkColor) {
  const bark = trunkColor.clone();
  const heart = trunkColor.clone().offsetHSL(0.015, -0.18, 0.34);
  const tmp = new THREE.Color();
  for (let i = 0; i < fracs.length; i++) {
    const f = fracs[i]; // 1 = rim/bark, 0 = center/heartwood
    tmp.copy(heart).lerp(bark, f);
    tmp.offsetHSL((Math2.random() - 0.5) * 0.02, 0, (Math2.random() - 0.5) * 0.08);
    colorArray[i * 3] = tmp.r;
    colorArray[i * 3 + 1] = tmp.g;
    colorArray[i * 3 + 2] = tmp.b;
  }
}

// Build the cap that closes a main branch's open lathe end. Non-cut-off branches
// taper to a thin tip and get a simple flat bark disk (isEndCap, recolored by the
// shared traverse pass). Cut-off branches get a torn break: concentric jagged
// rings that recede into the trunk toward a deep center, colored bark→heartwood,
// so it reads as snapped wood with the interior growth levels exposed.
createMainBranchEndCap(centerline, endRadius, isCutOff) {
  if (!centerline || centerline.length < 2) return null;

  const tip = centerline[centerline.length - 1];
  const prev = centerline[centerline.length - 2];
  const center = new THREE.Vector3(tip.x, tip.y, tip.z);
  const dir = new THREE.Vector3(tip.x - prev.x, tip.y - prev.y, tip.z - prev.z);
  if (dir.lengthSq() < 1e-6) dir.set(0, 1, 0);
  dir.normalize();

  if (!isCutOff) {
    // Clean tip: just close the small hole with a flat bark disk.
    // The lathe's end ring sits at a constant local Y (lean/noise only shift its
    // vertices sideways, never tilt the ring), so the disk must face straight up
    // local +Y — orienting it to the lean-tilted centerline tangent skews it a few
    // degrees off the actual opening.
    const capGeometry = new THREE.CircleGeometry(Math.max(endRadius, 0.5) * 0.908, 6);
    const capMaterial = new THREE.MeshStandardMaterial({
      color: new THREE.Color(parameters.truncColor).offsetHSL(0, -0.1, 0.3),
      roughness: 0.7,
      metalness: 0.1,
      flatShading: true
    });
    const cap = new THREE.Mesh(capGeometry, capMaterial);
    cap.userData.isEndCap = true; // recolored by updateTrunkColor's traverse pass
    // Sink the disk a touch into the tube so the bark rim reads as a lip around it,
    // rather than a flush-soldered end.
    cap.position.copy(center).add(dir.clone().multiplyScalar(-Math.max(endRadius, 0.6) * 0.15));
    // Aim along the branch tangent, nudged slightly toward local +Y to take a bit
    // of the lean tilt off the disk — without going all the way to straight-up,
    // which is lookAt's degenerate (parallel-to-up) case.
    const faceDir = dir.clone().lerp(new THREE.Vector3(0, 1, 0), 0.35).normalize();
    cap.lookAt(cap.position.clone().add(faceDir));
    // Spin the hexagon in its own plane. Negative = clockwise (as seen looking at
    // the cap face); bump the magnitude to rotate it further.
    cap.rotateZ(-0.2);
    // Bake that orientation/offset into the geometry and zero the mesh transform so
    // the disk lives in the same group-local frame as the lathe. That lets
    // updateMainBranchThickness shrink it with a plain x/z scale (like the tube),
    // instead of leaving it flared out past a thinned branch.
    cap.updateMatrix();
    cap.geometry.applyMatrix4(cap.matrix);
    cap.position.set(0, 0, 0);
    cap.quaternion.identity();
    cap.scale.set(1, 1, 1);
    cap.castShadow = true;
    cap.receiveShadow = true;
    return cap;
  }

  // Broken end. Lay out concentric rings perpendicular to the branch axis, each
  // pushed back into the branch (deeper toward the center) with per-vertex jitter
  // so the rim is ragged and the interior dishes inward like a snapped stub.
  const segments = 8;
  const ringFracs = [1.0, 0.66, 0.36, 0.0]; // rim → center (0 collapses to a point)
  const depth = Math.max(endRadius, 0.8) * 0.6; // how far the center dishes in

  // Build the break in the tube's end-ring plane (constant local +Y), not around
  // the lean-tilted tangent — orienting it to the tangent tips the rim plane and
  // opens a gap on one side where it lifts off the wall.
  const axis = new THREE.Vector3(0, 1, 0);
  const ref = new THREE.Vector3(1, 0, 0);
  const u = new THREE.Vector3().crossVectors(axis, ref).normalize();
  const v = new THREE.Vector3().crossVectors(axis, u).normalize();

  const rings = [];
  for (let r = 0; r < ringFracs.length; r++) {
    const frac = ringFracs[r];
    const isCenter = frac === 0;
    const isRim = r === 0;
    const count = isCenter ? 1 : segments;
    const baseRadius = (isRim ? 1.0 : 0.9) * endRadius * frac; // rim meets the wall
    const rowDepth = depth * Math.pow(1 - frac, 1.4);
    const ring = [];
    for (let s = 0; s < count; s++) {
      const a = (s / segments) * Math.PI * 2;
      // Rim jitters outward only so it never dips inside the wall (gap); inner
      // rings stay ragged both ways.
      const radJag = isCenter ? 0
        : isRim ? 1 + Math2.random() * 0.06
        : 1 + (Math2.random() - 0.5) * 0.18;
      const rr = baseRadius * radJag;
      const jagDepth = (Math2.random() - 0.5) * depth * 0.35;
      const pos = center.clone()
        .add(u.clone().multiplyScalar(Math.cos(a) * rr))
        .add(v.clone().multiplyScalar(Math.sin(a) * rr))
        .add(axis.clone().multiplyScalar(-(rowDepth + jagDepth)));
      ring.push({ pos, frac });
    }
    rings.push(ring);
  }

  const positions = [];
  const fracs = [];
  const pushVert = (vert) => {
    positions.push(vert.pos.x, vert.pos.y, vert.pos.z);
    fracs.push(vert.frac);
  };

  for (let r = 0; r < rings.length - 1; r++) {
    const outer = rings[r];
    const inner = rings[r + 1];
    if (inner.length === 1) {
      const c = inner[0];
      for (let s = 0; s < segments; s++) {
        pushVert(outer[s]);
        pushVert(outer[(s + 1) % segments]);
        pushVert(c);
      }
    } else {
      for (let s = 0; s < segments; s++) {
        const o0 = outer[s], o1 = outer[(s + 1) % segments];
        const i0 = inner[s], i1 = inner[(s + 1) % segments];
        pushVert(o0); pushVert(o1); pushVert(i1);
        pushVert(o0); pushVert(i1); pushVert(i0);
      }
    }
  }

  const geom = new THREE.BufferGeometry();
  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  const capFracs = new Float32Array(fracs);
  const colorArray = new Float32Array(fracs.length * 3);
  this._fillBrokenCapColors(colorArray, capFracs, new THREE.Color(parameters.truncColor));
  geom.setAttribute('color', new THREE.BufferAttribute(colorArray, 3));
  geom.computeVertexNormals();

  const mat = new THREE.MeshStandardMaterial({
    vertexColors: true,
    roughness: 0.85,
    metalness: 0.1,
    flatShading: true,
    side: THREE.DoubleSide
  });
  const cap = new THREE.Mesh(geom, mat);
  cap.userData.isBrokenCap = true;       // skipped by updateMainBranchColors
  cap.userData.capFracs = capFracs;      // so updateTrunkColor can repaint the gradient
  cap.castShadow = true;
  cap.receiveShadow = true;
  return cap;
}

extractMainBranchCenterline(geometryPositions, originalPoints, branchLength) {
  const centerlineData = [];
  
  // Group vertices by Y position (height along the branch)
  const heightGroups = {};
  
  // Group vertices by height
  for (let i = 0; i < geometryPositions.count; i++) {
    const x = geometryPositions.getX(i);
    const y = geometryPositions.getY(i);
    const z = geometryPositions.getZ(i);
    
    const heightKey = Math.round(y * 10) / 10; // Round to nearest 0.1
    
    if (!heightGroups[heightKey]) {
      heightGroups[heightKey] = [];
    }
    heightGroups[heightKey].push({ x, y, z });
  }
  
  // Calculate center point for each height
  Object.keys(heightGroups).sort((a, b) => parseFloat(a) - parseFloat(b)).forEach(heightKey => {
    const vertices = heightGroups[heightKey];
    let centerX = 0, centerY = 0, centerZ = 0;
    
    vertices.forEach(vertex => {
      centerX += vertex.x;
      centerY += vertex.y;
      centerZ += vertex.z;
    });
    
    centerX /= vertices.length;
    centerY /= vertices.length;
    centerZ /= vertices.length;
    
    // Find corresponding radius from original points
    const y = centerY;
    const t = y / branchLength;
    let radius = originalPoints[0].x * Math.pow(1 - t, 1.2); // Use original thickness calculation
    radius = Math.max(radius, 0.2);
    
    centerlineData.push({
      x: centerX,
      y: centerY,
      z: centerZ,
      radius: radius
    });
  });
  
  return centerlineData;
}

// Position + radius along a main branch's centerline at an arbitrary height,
// interpolating between the two bracketing samples (same rationale as
// getTrunkPositionAtHeight: snapping leaves sub-branches off a curved main branch).
getMainBranchPositionAtHeight(centerline, targetHeight) {
  if (!centerline || centerline.length < 2) {
    return { x: 0, y: targetHeight, z: 0, radius: 2 };
  }

  if (targetHeight <= centerline[0].y) {
    const p = centerline[0];
    return { x: p.x, y: targetHeight, z: p.z, radius: p.radius };
  }
  const last = centerline[centerline.length - 1];
  if (targetHeight >= last.y) {
    return { x: last.x, y: targetHeight, z: last.z, radius: last.radius };
  }

  for (let i = 1; i < centerline.length; i++) {
    const b = centerline[i];
    if (targetHeight <= b.y) {
      const a = centerline[i - 1];
      const span = b.y - a.y;
      const f = span > 0 ? (targetHeight - a.y) / span : 0;
      return {
        x: a.x + (b.x - a.x) * f,
        y: targetHeight,
        z: a.z + (b.z - a.z) * f,
        radius: a.radius + (b.radius - a.radius) * f
      };
    }
  }

  return { x: last.x, y: targetHeight, z: last.z, radius: last.radius };
}

updateMainBranchColors(branchGroup, newTrunkColor) {
  
  branchGroup.children.forEach((child, childIndex) => {
    
    // Broken end caps also use vertex colors, but carry a bark→heartwood gradient
    // (not the bark-by-length scheme below); they're repainted in the traverse pass.
    if (child.userData && child.userData.isBrokenCap) return;

    // Handle main branch meshes and interior meshes
    if (child.material && child.material.vertexColors && child.geometry.attributes.color) {
      
      const colors = child.geometry.attributes.color.array;
      const positions = child.geometry.attributes.position;
      
      // Find the maximum Y value for length calculation
      let maxY = -Infinity;
      for (let i = 0; i < positions.count; i++) {
        const y = positions.getY(i);
        if (y > maxY) maxY = y;
      }
      
      for (let i = 0; i < positions.count; i++) {
        const y = positions.getY(i);
        const lengthRatio = maxY > 0 ? y / maxY : 0;
        
        let color;
        if (child.userData.isMainBranchInterior) {
          // Lighter color for interior
          color = newTrunkColor.clone();
          color.offsetHSL(0, -0.1, 0.2);
          color.offsetHSL(0, 0, lengthRatio * 0.1 - 0.05);
        } else {
          // Regular branch color
          color = newTrunkColor.clone();
          color.offsetHSL(0, 0, lengthRatio * 0.2 - 0.1);
        }

        color.offsetHSL((Math2.random() - 0.5) * 0.05, 0, (Math2.random() - 0.5) * 0.1);

        const colorIndex = i * 3;
        colors[colorIndex] = color.r;
        colors[colorIndex + 1] = color.g;
        colors[colorIndex + 2] = color.b;
      }

      child.geometry.attributes.color.needsUpdate = true;
      // The birch texture belongs only on the outer bark, not the interior wood.
      if (!child.userData.isMainBranchInterior) syncBirchTexture(child.material);
    }
    
    // NEW: Handle sub-branch groups (created by addBranchesToMainBranch)
    else if (child.type === 'Group' && child.children.length > 0) {
      this.updateSubBranchColors(child, newTrunkColor);
    }
  });
}

pruneMainBranch(branchGroup, instant = false) {
  if (instant) { this.mesh.remove(branchGroup); return; }
  gsap.to(branchGroup.scale, {
    x: 0.01, y: 0.01, z: 0.01,
    duration: 0.8,
    ease: "power2.in",
    onComplete: () => {
      this.mesh.remove(branchGroup);
    }
  });
}

// --- Partial pruning of MAIN branches --------------------------------------
// A main branch is a lathe of `latheProfileCount` rings stacked along its length.
// Pruning keeps rings [0, k] and drops everything past ring k — the lathe-mesh
// equivalent of Branch.cutAt's tube truncation. Because the rings are ordered up
// the branch, "cut at ring k" is just an index filter: keep faces whose lower
// profile row is < k, drop the rest. The dropped faces become the falling offcut.

// Split a lathe geometry's triangles into the stub (rings [0,k]) and the offcut
// (rings [k, tip]). A face spans profile rows j and j+1; its row is min(rows), so
// faces with row < k stay on the stub and the rest fall away. Vertex index maps to
// its profile row as index % P (LatheGeometry lays out vertices phi-major).
_splitLatheIndex(geometry, P, k) {
  const idx = geometry.index.array;
  const stub = [], offcut = [];
  for (let f = 0; f < idx.length; f += 3) {
    const a = idx[f], b = idx[f + 1], c = idx[f + 2];
    const row = Math.min(a % P, b % P, c % P);
    (row < k ? stub : offcut).push(a, b, c);
  }
  return { stub, offcut };
}

// Map a world-space hit on a main branch to the ring it would be cut at: 0 (cut at
// the base = whole-branch removal) through cutRing-1 (lop off just the tip ring).
// Always returns a removable ring so pointing anywhere on the branch cuts from
// there outward; null only if the branch has no geometry. The bias (+0.2) makes a
// segment start pruning ~20% in, matching Branch.cutRingForPoint.
cutRingForMainBranch(group, worldPoint) {
  const c = group.userData.centerline;
  const tipRing = group.userData.cutRing != null
    ? group.userData.cutRing : ((group.userData.latheProfileCount || 1) - 1);
  if (!c || c.length < 2 || tipRing < 1) return null;

  group.updateWorldMatrix(true, false);
  const localY = group.worldToLocal(worldPoint.clone()).y; // height along the branch axis

  // Continuous ring position from localY (rings sit at centerline[j].y).
  let r;
  if (localY <= c[0].y) {
    r = 0;
  } else {
    r = c.length - 1;
    for (let j = 1; j < c.length; j++) {
      if (localY <= c[j].y) {
        r = (j - 1) + (localY - c[j - 1].y) / ((c[j].y - c[j - 1].y) || 1);
        break;
      }
    }
  }

  // keep rings [0,k], remove (k, tip]; clamp so the tip ring is the deepest cut.
  return THREE.MathUtils.clamp(Math.floor(r + 0.2), 0, tipRing - 1);
}

// Red-tint the offcut (the wood + sub-branches a click at ring k would remove) so
// the hover previews the cut, mirroring Branch.previewCut. Whole-branch removal
// (k === 0) is previewed by interaction.js's setMainBranchHighlight instead.
previewMainBranchCut(group, k) {
  this.clearMainBranchCutPreview(group);
  const P = group.userData.latheProfileCount;
  const c = group.userData.centerline;
  if (P == null || !c) return;
  const outer = group.children.find(m => m.userData && m.userData.isMainBranch);
  if (!outer) return;

  const preview = { meshes: [], doomed: [] };

  const { offcut } = this._splitLatheIndex(outer.geometry, P, k);
  if (offcut.length) {
    const geo = outer.geometry.clone();
    geo.setIndex(offcut);
    const overlay = new THREE.Mesh(geo, new THREE.MeshBasicMaterial({ color: 0xd21a1a }));
    overlay.raycast = () => {};                 // don't intercept hover picking
    overlay.scale.set(outer.scale.x * 1.06, 1, outer.scale.z * 1.06); // just outside the bark
    group.add(overlay);
    preview.meshes.push(overlay);
  }

  const cutY = c[Math.min(k, c.length - 1)].y;
  group.children.forEach(child => {
    const sub = child.userData && child.userData.branch;
    if (sub && !sub.isPruned && sub.parentHeight != null && sub.parentHeight > cutY) {
      sub.previewDoomed();
      preview.doomed.push(sub);
    }
  });

  group.userData._cutPreview = preview;
}

clearMainBranchCutPreview(group) {
  const preview = group.userData._cutPreview;
  if (!preview) return;
  preview.meshes.forEach(m => { group.remove(m); m.geometry.dispose(); m.material.dispose(); });
  preview.doomed.forEach(sub => sub.restoreDoomed());
  group.userData._cutPreview = null;
}

// Lop the main branch off at ring k: keep rings [0,k], drop the rest (wood, the old
// end cap, and any sub-branch whose base sits past the cut) as a falling offcut, and
// re-cap the fresh stub with a torn break. k <= 0 removes the whole branch; k at/past
// the current tip is a no-op. `instant` (save/replay) applies the same end state
// without the falling animation. Mirrors Branch.cutAt for main branches.
pruneMainBranchAt(group, k, instant = false) {
  this.clearMainBranchCutPreview(group);
  const gud = group.userData;
  const P = gud.latheProfileCount;
  const c = gud.centerline;
  if (P == null || !c) return;
  const tipRing = gud.cutRing != null ? gud.cutRing : (P - 1);
  if (k <= 0) { this.pruneMainBranch(group, instant); return; }
  if (k >= tipRing) return;

  // Debris is assembled in the group's local space (so offcut pieces keep their
  // place), then re-parented to the scene root to fall straight down.
  const debris = instant ? null : new THREE.Group();
  if (debris) group.add(debris);

  // Truncate every lathe mesh (outer bark + interior layers); hand the offcut faces
  // to the debris as standalone meshes that share the same local transform.
  group.children.forEach(mesh => {
    const ud = mesh.userData;
    if (!ud || !(ud.isMainBranch || ud.isMainBranchInterior)) return;
    const { stub, offcut } = this._splitLatheIndex(mesh.geometry, P, k);
    if (debris && offcut.length) {
      const geo = mesh.geometry.clone();
      geo.setIndex(offcut);
      const off = new THREE.Mesh(geo, mesh.material.clone());
      off.castShadow = true;
      off.position.copy(mesh.position);
      off.rotation.copy(mesh.rotation);
      off.scale.copy(mesh.scale);
      debris.add(off);
    }
    mesh.geometry.setIndex(stub);
  });

  // Sub-branches past the cut fall with the offcut; the rest stay on the stub.
  const cutY = c[Math.min(k, c.length - 1)].y;
  [...group.children].forEach(child => {
    const sub = child.userData && child.userData.branch;
    if (sub && !sub.isPruned && sub.parentHeight != null && sub.parentHeight > cutY) {
      if (debris) debris.add(sub.mesh); else group.remove(sub.mesh);
      sub.isPruned = true;
    }
  });

  // The old tip cap falls with the offcut; the fresh stub gets a new torn break.
  [...group.children].forEach(child => {
    const ud = child.userData;
    if (ud && (ud.isEndCap || ud.isBrokenCap)) {
      if (debris) debris.add(child); else group.remove(child);
    }
  });
  const tip = c[k];
  const prev = c[Math.max(k - 1, 0)];
  const newCap = this.createMainBranchEndCap([prev, tip], tip.radius, true);
  if (newCap) {
    // The cap is built at the branch's as-built (unscaled) radius, so match the
    // current thickness scale the rest of the branch carries — otherwise a stub
    // cut after the thickness slider was lowered pops back to full girth.
    if (gud.buildBaseRadius) {
      const s = Math.min(1, this.baseRadius / gud.buildBaseRadius);
      newCap.scale.x = s;
      newCap.scale.z = s;
    }
    group.add(newCap);
  }

  // Record the new (shorter) length so curve drags and further prunes clip to it.
  gud.cutRing = k;
  gud.centerline = c.slice(0, k + 1);

  if (!debris) return;

  // Re-parent to the scene root (preserving world transform) so "down" is world-down,
  // then fall + fade out — same as Branch.cutAt's offcut.
  let root = this.mesh; while (root.parent) root = root.parent;
  root.attach(debris);
  const materials = [];
  debris.traverse(o => { if (o.material) { o.material.transparent = true; materials.push(o.material); } });
  gsap.to(debris.position, { y: '-=22', duration: 0.9, ease: 'power1.in' });
  gsap.to(materials, {
    opacity: 0,
    duration: 0.9,
    ease: 'power2.in',
    onComplete: () => { root.remove(debris); materials.forEach(m => m.dispose()); }
  });
}

// Sub-branch method for main branches
addBranchesToMainBranch(mainBranchGroup, mainBranchLength, mainBranchThickness) {
  const numSubBranches = Math2.rangeRandomInt(2, 5); // 2-4 sub-branches per main branch
  const centerline = mainBranchGroup.userData.centerline;
  
  if (!centerline || centerline.length === 0) {
    console.warn('No centerline data available for main branch, falling back to simple positioning');
    this.addBranchesToMainBranchFallback(mainBranchGroup, mainBranchLength, mainBranchThickness);
    return;
  }
  
  for (let i = 0; i < numSubBranches; i++) {
    const t = 0.3 + (i / numSubBranches) * 0.6; // Position along main branch (30% to 90%)
    const subBranchHeight = mainBranchLength * t;
    
    // Get the ACTUAL position along the transformed main branch
    const branchPos = this.getMainBranchPositionAtHeight(centerline, subBranchHeight);

    // Calculate position around the main branch at this specific point
    const angle = (Math2.random() * Math.PI * 2); // Random angle around main branch

    // Create sub-branch with thickness proportional to the main branch radius at this height
    const subBranchLength = mainBranchLength * (0.7 - t * 0.6 + Math2.random() * 0.15); // 30-70% of main branch length
    const subBranchThickness = branchPos.radius * (0.4 + Math2.random() * 0.2); // 40-60% of main branch radius at this height

    // Pass the parent CENTERLINE position (not an outward-offset surface point) so the
    // Branch constructor's penetration sinks the base INTO the main branch instead of
    // stacking a second outward offset on top — otherwise thin tip sub-branches float off.
    const subBranch = new Branch(
      subBranchLength,
      subBranchThickness,
      angle,
      { x: branchPos.x, y: branchPos.y, z: branchPos.z, radius: branchPos.radius },
      i
    );

    // Stable id for save/replay: parent main id + a per-main running sub index.
    subBranch.mesh.userData.branch = subBranch;
    subBranch.branchId = (mainBranchGroup.userData.branchId || 'm#?') + '/s#' + (mainBranchGroup.userData.subCount++);
    // Height along the parent main branch, so it can be re-placed onto the bent
    // centerline when the Curve slider reshapes the main branch (see updateMainBranchShape).
    subBranch.parentHeight = subBranchHeight;

    mainBranchGroup.add(subBranch.mesh);
  }
}

// NEW: Fallback method in case centerline extraction fails
addBranchesToMainBranchFallback(mainBranchGroup, mainBranchLength, mainBranchThickness) {
  const numSubBranches = Math2.rangeRandomInt(2, 5);
  
  for (let i = 0; i < numSubBranches; i++) {
    const t = 0.3 + (i / numSubBranches) * 0.6;
    const subBranchHeight = mainBranchLength * t;
    
    // Simple positioning without centerline data: base sits on the branch axis and the
    // constructor's penetration carries it outward, so it stays embedded in the parent.
    const radiusAtHeight = mainBranchThickness * Math.pow(1 - t, 1.2);
    const angle = (Math2.random() * Math.PI * 2);

    const subBranchLength = mainBranchLength * (0.7 - t * 0.6 + Math2.random() * 0.15);
    const subBranchThickness = radiusAtHeight * (0.02 + Math2.random() * 0.05);

    const subBranch = new Branch(
      subBranchLength,
      subBranchThickness,
      angle,
      { x: 0, y: subBranchHeight, z: 0, radius: radiusAtHeight },
      i
    );

    subBranch.mesh.userData.branch = subBranch;
    subBranch.branchId = (mainBranchGroup.userData.branchId || 'm#?') + '/s#' + (mainBranchGroup.userData.subCount++);
    subBranch.parentHeight = subBranchHeight;

    mainBranchGroup.add(subBranch.mesh);
  }
}

// New method to extract the actual trunk centerline from the geometry
extractTrunkCenterline(geometryPositions, originalPoints) {
  this.trunkCurveData = [];
  
  // For each height level, find the center point of all vertices at that height
  const heightGroups = {};
  
  // Group vertices by height
  for (let i = 0; i < geometryPositions.count; i++) {
    const x = geometryPositions.getX(i);
    const y = geometryPositions.getY(i);
    const z = geometryPositions.getZ(i);
    
    const heightKey = Math.round(y * 10) / 10; // Round to nearest 0.1
    
    if (!heightGroups[heightKey]) {
      heightGroups[heightKey] = [];
    }
    heightGroups[heightKey].push({ x, y, z });
  }
  
  // Calculate center point for each height
  Object.keys(heightGroups).sort((a, b) => parseFloat(a) - parseFloat(b)).forEach(heightKey => {
    const vertices = heightGroups[heightKey];
    let centerX = 0, centerY = 0, centerZ = 0;
    
    vertices.forEach(vertex => {
      centerX += vertex.x;
      centerY += vertex.y;
      centerZ += vertex.z;
    });
    
    centerX /= vertices.length;
    centerY /= vertices.length;
    centerZ /= vertices.length;
    
    // Find corresponding radius from original points
    const y = centerY;
    const t = y / this.height;
    let radius = this.baseRadius * Math.pow(1 - t, 1.5);
    radius = Math.max(radius, 0.2);
    
    this.trunkCurveData.push({
      x: centerX,
      y: centerY,
      z: centerZ,
      radius: radius
    });
  });
}

// Return the trunk centerline position + radius at an arbitrary height by
// INTERPOLATING between the two bracketing curve samples (trunkCurveData is sorted
// by y ascending). Snapping to the nearest sample instead used to place a branch at
// the x/z of a slightly different height — invisible inside the fat lower trunk, but
// a visible gap on the thin, leaning upper trunk (the "consistently detached" branch).
getTrunkPositionAtHeight(targetHeight) {
  const curve = this.trunkCurveData;
  if (!curve || curve.length < 2) {
    return { x: 0, y: targetHeight, z: 0, radius: this.baseRadius || 4 };
  }

  // Clamp below/above the sampled range to the end samples.
  if (targetHeight <= curve[0].y) {
    return { x: curve[0].x, y: targetHeight, z: curve[0].z, radius: curve[0].radius };
  }
  const last = curve[curve.length - 1];
  if (targetHeight >= last.y) {
    return { x: last.x, y: targetHeight, z: last.z, radius: last.radius };
  }

  // Find the bracketing pair [a, b] with a.y <= targetHeight <= b.y and lerp.
  for (let i = 1; i < curve.length; i++) {
    const b = curve[i];
    if (targetHeight <= b.y) {
      const a = curve[i - 1];
      const span = b.y - a.y;
      const f = span > 0 ? (targetHeight - a.y) / span : 0;
      return {
        x: a.x + (b.x - a.x) * f,
        y: targetHeight,
        z: a.z + (b.z - a.z) * f,
        radius: a.radius + (b.radius - a.radius) * f
      };
    }
  }

  return { x: last.x, y: targetHeight, z: last.z, radius: last.radius };
}

// Create branch geometry
createBranches() {
  const branchCount = 8; // Fixed number of branches - no longer uses foliageDensity
  const height = parameters.truncHeight;
  const actualTrunkEndHeight = this.trunkEndHeight || height;
  
  // Clear existing branches
  this.branches.forEach(branch => {
    this.mesh.remove(branch.mesh);
  });
  this.branches = [];

  // Create branches at different heights with proper trunk connection
  for (let i = 0; i < branchCount; i++) {
    const heightRatio = 0.5 + (i / branchCount) * 0.55; // Branches from 50% to 95% of trunk height
    const branchHeight = actualTrunkEndHeight * heightRatio;
    
    // Get the actual trunk position and radius at this height
    const trunkPos = this.getTrunkPositionAtHeight(branchHeight);
    
    // Calculate branch angle
    const angle = (i / branchCount) * Math.PI * 2.6 + Math2.random() * 0.33;

    const branchLength = actualTrunkEndHeight * (1 - heightRatio) * 0.8;
    
    const branch = new Branch(
      branchLength,
      trunkPos.radius * 0.3,
      angle,
      trunkPos,
      i
    );
    branch.heightRatio = heightRatio; // for re-attaching when the trunk is reshaped
    branch.branchId = 'b#' + i; // stable id for save/replay (trunk branch slot)

    this.branches.push(branch);
    this.mesh.add(branch.mesh);
  }
}

addMoreBranches() {
  const currentBranchCount = this.branches.length;
  const newBranchCount = Math.min(currentBranchCount + 2, 22);
  const actualTrunkEndHeight = this.trunkEndHeight || parameters.truncHeight;
  
  for (let i = currentBranchCount; i < newBranchCount; i++) {
    const heightRatio = Math2.random() * 0.5 + 0.4; // 40% to 90% of actual trunk height
    const branchHeight = actualTrunkEndHeight * heightRatio;
    
    // Get the actual trunk position at this height
    const trunkPos = this.getTrunkPositionAtHeight(branchHeight);
    
    const angle = Math2.random() * Math.PI * 2;
    
    const branch = new Branch(
      actualTrunkEndHeight * (1 - heightRatio) * 0.8,     // Branch length
      trunkPos.radius * 0.25,                             // Branch thickness
      angle,
      trunkPos,
      i
    );
    branch.heightRatio = heightRatio; // for re-attaching when the trunk is reshaped
    branch.branchId = 'b#' + i; // stable id for save/replay (trunk branch slot)

    this.branches.push(branch);
    this.mesh.add(branch.mesh);

    // Animate new branch growth
    branch.mesh.scale.set(0.01, 0.01, 0.01);
    gsap.to(branch.mesh.scale, {
      x: 1, y: 1, z: 1,
      duration: 1.5,
      ease: "back.out(1.7)",
      delay: (i - currentBranchCount) * 0.2
    });
  }
}

// Method 2: Add sub-branches to existing main branches
addMoreSubBranches() {
  // Find all main branch groups
  const mainBranches = this.mesh.children.filter(child => 
    child.userData && child.userData.isMainBranch
  );
  
  if (mainBranches.length === 0) {
    return;
  }
  
  // Randomly select 1-2 main branches to add sub-branches to
  const branchesToGrow = Math.min(Math2.rangeRandomInt(1, 3), mainBranches.length);
  
  for (let i = 0; i < branchesToGrow; i++) {
    const randomMainBranch = mainBranches[Math.floor(Math2.random() * mainBranches.length)];
    this.addSubBranchToMainBranch(randomMainBranch);
  }
}

// Sprout extra twigs on branches that ALREADY exist, so the grow button thickens
// the canopy of older growth too — not only the freshly added branches (which get
// their twigs from the Branch constructor). Picks a random handful of eligible
// branches and grows a couple of animated twigs on each.
growMoreTwigs() {
  // Collect every live, twig-capable branch anywhere in the tree (trunk branches
  // + main-branch sub-branches). userData.branch can sit on a branch's group or
  // its wood mesh, so dedupe with a Set. Twigs and too-thin branches are skipped.
  const seen = new Set();
  const candidates = [];
  const collect = (obj) => {
    const b = obj.userData && obj.userData.branch;
    if (b && !seen.has(b)) {
      seen.add(b);
      if (!b.isPruned && !b.isTwig && b.thickness >= TWIG_MIN_PARENT_THICKNESS) candidates.push(b);
    }
    if (obj.children) obj.children.forEach(collect);
  };
  collect(this.mesh);

  if (candidates.length === 0) return;

  const count = Math.min(Math2.rangeRandomInt(2, 5), candidates.length); // bush out 2-4 of them
  for (let i = 0; i < count; i++) {
    candidates[Math.floor(Math2.random() * candidates.length)].growTwigs();
  }
}

// Method 3: Add a sub-branch to a specific main branch
addSubBranchToMainBranch(mainBranchGroup) {
  // Get the centerline data from the main branch
  const centerline = mainBranchGroup.userData.centerline;
  
  // Get the main branch dimensions.
  let mainBranchLength = 50; // Default fallback
  let mainBranchThickness = 4;

  if (centerline && centerline.length > 1) {
    // Use the centerline, which is clipped back when the branch is pruned, so new
    // sub-branches land on the SURVIVING stub rather than out where the branch used
    // to reach. (A partial prune only drops faces — the lopped-off lathe vertices
    // remain, so a geometry bounding box would still report the full length.)
    mainBranchLength = centerline[centerline.length - 1].y;
    mainBranchThickness = centerline[0].radius;
  } else {
    // No centerline: fall back to the geometry bounds.
    const mainBranchMesh = mainBranchGroup.children.find(child =>
      child.type === 'Mesh' && !child.userData.isMainBranchInterior
    );
    if (mainBranchMesh && mainBranchMesh.geometry) {
      const box = new THREE.Box3().setFromObject(mainBranchMesh);
      mainBranchLength = Math.max(box.max.y - box.min.y, box.max.z - box.min.z, box.max.x - box.min.x);
      mainBranchThickness = Math.min(box.max.x - box.min.x, box.max.z - box.min.z) * 0.5;
    }
  }
  
  // Add 1-2 new sub-branches to this main branch
  const numNewSubBranches = Math2.rangeRandomInt(1, 3);
  
  for (let i = 0; i < numNewSubBranches; i++) {
    const t = 0.3 + Math2.random() * 0.6; // Position along main branch (30% to 90%)
    const subBranchHeight = mainBranchLength * t;
    
    let branchPos, radiusAtHeight;
    // Single angle drives BOTH the growth direction and the constructor's penetration, so
    // the base sinks into the parent along the same axis the branch grows out of. (Previously
    // the offset used one random angle and the constructor a different one, leaving thin
    // tip sub-branches floating.)
    const angle = Math2.random() * Math.PI * 2;

    if (centerline && centerline.length > 0) {
      // Use centerline for accurate positioning
      branchPos = this.getMainBranchPositionAtHeight(centerline, subBranchHeight);
      radiusAtHeight = branchPos.radius;
    } else {
      // Fallback to simple calculation: base on the branch axis; penetration carries it out.
      console.warn('No centerline available, using fallback positioning');
      radiusAtHeight = mainBranchThickness * Math.pow(1 - t, 1.2);
      branchPos = { x: 0, y: subBranchHeight, z: 0, radius: radiusAtHeight };
    }

    // PROPER SIZING RULES: Higher branches (larger t values) should be shorter and thinner
    const remainingLength = 1 - t;
    const subBranchLength = mainBranchLength * (1 - t) * (0.6 + Math2.random() * 0.3);
    const subBranchThickness = radiusAtHeight * (0.3 - t * 0.2 + Math2.random() * 0.1);

    const subBranch = new Branch(
      subBranchLength,
      subBranchThickness,
      angle,
      branchPos,
      Date.now() + i // Use timestamp for unique ID
    );
    
    // Store reference to branch object for future updates
    subBranch.mesh.userData.branch = subBranch;
    subBranch.branchId = (mainBranchGroup.userData.branchId || 'm#?') + '/s#' + (mainBranchGroup.userData.subCount++);
    // Height along the parent, so the Curve slider can re-place it (updateMainBranchShape).
    subBranch.parentHeight = subBranchHeight;

    // Animate the new sub-branch growth
    subBranch.mesh.scale.set(0.01, 0.01, 0.01);
    gsap.to(subBranch.mesh.scale, {
      x: 1, y: 1, z: 1,
      duration: 1.5,
      ease: "back.out(1.7)",
      delay: i * 0.3
    });
    
    mainBranchGroup.add(subBranch.mesh);
  }
}

// Add `count` main branches off the trunk, sized/placed via the seeded RNG so the
// layout is reproducible. Shared by the "main branches" button (which records the
// action) and by history replay. With animate=false (replay) branches appear at
// full scale immediately. NOTE: gsap timing jitter stays on Math.random (cosmetic)
// so it never perturbs the seeded stream replay depends on.
addMainBranches(count, animate = true) {
  for (let i = 0; i < count; i++) {
    const heightRatio = 0.015 + Math2.random() * 0.28;
    const branchHeight = this.height * heightRatio;
    const trunkPos = this.getTrunkPositionAtHeight(branchHeight);

    const branchLength = this.height * (0.4 + Math2.random() * 0.3);
    const branchThickness = this.baseRadius * (0.6 + Math2.random() * 0.2);
    const angle = Math2.random() * Math.PI * 2;

    const mainBranch = this.createMainBranch(
      branchLength, branchThickness, angle, trunkPos, this._mainSeq++
    );
    this.mesh.add(mainBranch);

    if (animate) {
      mainBranch.scale.set(0.01, 0.01, 0.01);
      gsap.to(mainBranch.scale, {
        x: 1, y: 1, z: 1,
        duration: 1.5 + Math.random() * 0.5, // cosmetic timing — off the seeded stream
        ease: "back.out(1.7)",
        delay: i * 0.4
      });
    }
  }
}

// ---- Save / replay support ----------------------------------------------
//
// Deterministic per-action sub-seed. Each recorded action re-seeds the RNG from
// this before it runs, keyed by its slot in the history log. That isolates an
// action's randomness from anything drawn BETWEEN actions (e.g. live trunk-slider
// rebuilds re-noise the bark and consume the stream), so a save replays faithfully
// no matter what untracked draws happened in the session. The index matches
// between recording (history.length) and replay (loop index), so the streams line up.
_seedForAction(index) {
  let a = (this.seed ^ Math.imul(index + 1, 0x9e3779b1)) >>> 0;
  a = Math.imul(a ^ (a >>> 16), 0x45d9f3b) >>> 0;
  a = Math.imul(a ^ (a >>> 16), 0x45d9f3b) >>> 0;
  Math2.seed((a ^ (a >>> 16)) >>> 0);
}

// Call right before performing a user action that will be record()ed: seeds the
// RNG for this action's history slot so the live result matches replay exactly.
beginRecordedAction() {
  this._seedForAction(this.history.length);
}

// How many main branches a single "main branches" action adds. Drawn from the
// seeded stream so replay reproduces the same count (mirrors the old inline
// max(1, rangeRandomInt(1,3)) in main.js).
mainBranchBatchSize() {
  return Math.max(1, Math2.rangeRandomInt(1, 3));
}

// Build maps branchId -> Branch (regular/sub) and branchId -> main-branch Group
// by walking the current scene graph — used to resolve prune/shape targets on
// replay. Rebuilt per lookup since the graph changes as edits are applied.
collectBranchIndex() {
  const branches = new Map();
  const mains = new Map();
  const walk = (obj) => {
    const b = obj.userData && obj.userData.branch;
    if (b && b.branchId && !branches.has(b.branchId)) branches.set(b.branchId, b);
    if (obj.type === 'Group' && obj.userData && obj.userData.isMainBranch && obj.userData.branchId) {
      mains.set(obj.userData.branchId, obj);
    }
    if (obj.children) obj.children.forEach(walk);
  };
  walk(this.mesh);
  return { branches, mains };
}

// Replay a saved edit log onto this (freshly seeded) tree to reproduce it
// exactly. Grow ops re-run the same seeded methods — so they consume the RNG
// stream identically and rebuild the same meshes — then prune/shape ops apply by
// id without animation. Order must match how the edits were originally made.
replayHistory(history) {
  if (!Array.isArray(history)) return;
  for (let i = 0; i < history.length; i++) {
    const entry = history[i];
    this._seedForAction(i); // match the seeding the live action used
    switch (entry.op) {
      case 'grow':
        if (entry.kind === 'addSubBranches') this.addMoreSubBranches();
        else this.addMoreBranches();
        this.growMoreTwigs();
        break;
      case 'mainBranches':
        this.addMainBranches(this.mainBranchBatchSize(), false);
        break;
      case 'cut': {
        const b = this.collectBranchIndex().branches.get(entry.id);
        if (b) b.cutAt(entry.ring, true);
        break;
      }
      case 'pruneMain': {
        const g = this.collectBranchIndex().mains.get(entry.id);
        // ring present = partial prune (lop off past ring k); absent = whole branch.
        if (g && entry.ring != null) this.pruneMainBranchAt(g, entry.ring, true);
        else if (g) this.pruneMainBranch(g, true);
        break;
      }
      case 'shape': {
        const idx = this.collectBranchIndex();
        if (entry.isMain) {
          const g = idx.mains.get(entry.id);
          if (g) { g.rotation.y = entry.ry; g.rotation.z = entry.rz; }
        } else {
          const b = idx.branches.get(entry.id);
          if (b && b.mesh) { b.mesh.rotation.y = entry.ry; b.mesh.rotation.z = entry.rz; }
        }
        break;
      }
    }
  }
}

    }

    class Branch {
      constructor(length, thickness, angle, trunkPos, branchIndex, isTwig = false) {
  this.mesh = new THREE.Group();
  this.length = length;
  this.thickness = thickness;
  this.angle = angle; // kept so the branch can re-attach if the trunk is reshaped
  this.isPruned = false;
  this.isTwig = isTwig; // a third-level branch; never sprouts further twigs

  // FIX: Adjust connection depth based on branch length
  // Longer branches need to go deeper into the trunk to look properly connected
  const basePenetration = trunkPos.radius * 0.3; // Base penetration
  const lengthFactor = Math.min(length / 50, 1.5); // Scale based on branch length
  const connectionDepth = basePenetration + (trunkPos.radius * 0.3 * lengthFactor);
  
  // Calculate position inside the trunk
  const x = trunkPos.x + Math.cos(angle) * connectionDepth;
  const z = trunkPos.z + Math.sin(angle) * connectionDepth;
  const y = trunkPos.y;
  
  this.mesh.position.set(x, y, z);
  
  // Calculate direction - point away from trunk center
  const directionX = Math.cos(angle);
  const directionZ = Math.sin(angle);
  
  // Set rotation to point outward and slightly up
  this.mesh.rotation.y = angle;
  this.mesh.rotation.z = -Math.PI * 0.1; // Slight upward angle

  this.createBranchGeometry();
  this.addFoliage();
  this.createEndCaps();
  this.addTwigs();
}

// Build and attach one twig at parameter `t` along this branch, returning it —
// or null if this branch can't carry twigs (it's a twig itself, too thin, or
// has no curve). Twigs are full Branch instances (own bark, end caps, foliage)
// parented to this branch's mesh, so they ride along when the branch is shaped,
// pruned, or recolored (foliage updates traverse recursively). Shared by the
// initial build (addTwigs) and later animated growth (growTwigs).
_spawnTwig(t) {
  if (this.isTwig || this.thickness < TWIG_MIN_PARENT_THICKNESS || !this.curve) return null;

  // A partial prune shrinks tipRing but leaves this.curve at full length, so a
  // twig sampled past the cut would float in thin air where the branch used to
  // reach. Clamp onto the surviving stub (a touch inside the tip so it sits on
  // wood, not past the cap). Done after the caller's RNG draw, so seeded replay
  // is unaffected — t still consumed the same random, we only relocate it.
  const tipFraction = this.tipRing / BRANCH_TUBULAR_SEGMENTS;
  t = Math.min(t, tipFraction * 0.95);

  const point = this.curve.getPoint(t);
  const tangent = this.curve.getTangent(t);

  // Twigs taper with the branch: ones near the thin outer end come in thinner
  // (and a touch shorter) than ones closer to the base. t spans 0.45–0.95.
  const taper = 1 - t * 0.6; // ~0.73 at the inner end, ~0.43 at the tip
  const twigLength = this.length * (0.3 + Math2.random() * 0.25) * (0.7 + taper * 0.3);
  const twigThickness = this.thickness * (0.4 + Math2.random() * 0.2) * taper;
  const splayAngle = Math2.random() * Math.PI * 2; // around the parent branch

  // trunkPos is unused here (twigs aren't trunk-attached); the Branch
  // constructor seeds position/rotation, then we override both to sit on the
  // parent's curve and angle the twig off it.
  const twig = new Branch(
    twigLength,
    twigThickness,
    splayAngle,
    { x: 0, y: 0, z: 0, radius: 0 },
    0,
    true // isTwig — stops the recursion at one extra level
  );

  twig.mesh.position.copy(point);
  twig.mesh.rotation.set(
    (Math2.random() - 0.5) * 0.9,                                  // tilt off the branch plane
    splayAngle,                                                    // splay around the branch
    Math.atan2(tangent.y, tangent.x) + (Math2.random() - 0.5) * 0.6 // roughly follow the branch, then diverge
  );

  this.mesh.add(twig.mesh);
  (this.twigs ||= []).push(twig);
  return twig;
}

// Sprout the initial third level of twigs along the outer half of this branch,
// where real trees fork. No-op on branches too thin to carry them.
addTwigs() {
  const numTwigs = Math2.rangeRandomInt(2, 5); // 2-4 twigs
  for (let i = 0; i < numTwigs; i++) this._spawnTwig(0.45 + Math2.random() * 0.5);
}

// Sprout a few MORE twigs on an already-built branch, animating each in — used
// by the grow button so existing branches keep getting bushier, not just new
// ones. Returns the number actually added (0 if the branch is too thin).
growTwigs() {
  const numNew = Math2.rangeRandomInt(1, 3); // 1-2 more
  let added = 0;
  for (let i = 0; i < numNew; i++) {
    const twig = this._spawnTwig(0.45 + Math2.random() * 0.5);
    if (!twig) break; // branch can't carry twigs; don't bother retrying
    twig.mesh.scale.set(0.01, 0.01, 0.01);
    gsap.to(twig.mesh.scale, {
      x: 1, y: 1, z: 1,
      duration: 1.2,
      ease: "back.out(1.7)",
      delay: i * 0.15
    });
    added++;
  }
  return added;
}

// Re-place this branch's base onto a (possibly reshaped) trunk position. Mirrors
// the connection math in the constructor; leaves rotation/geometry/foliage alone
// so user shaping is preserved.
reattach(trunkPos) {
  const basePenetration = trunkPos.radius * 0.3;
  const lengthFactor = Math.min(this.length / 50, 1.5);
  const connectionDepth = basePenetration + (trunkPos.radius * 0.3 * lengthFactor);
  this.mesh.position.set(
    trunkPos.x + Math.cos(this.angle) * connectionDepth,
    trunkPos.y,
    trunkPos.z + Math.sin(this.angle) * connectionDepth
  );
}

updateFoliageDensity() {
  if (!this.foliageGroup || this.isPruned) return;

  // Clear existing foliage
  while (this.foliageGroup.children.length > 0) {
    this.foliageGroup.remove(this.foliageGroup.children[0]);
  }
  
  // Recreate foliage with new density
  if (isNeedleType()) {
    this.createNeedles();
  } else {
    this.createDeciduousLeaves();
  }

  // Twigs carry their own foliage but aren't in tree.branches; recurse so their
  // density updates too.
  if (this.twigs) this.twigs.forEach(twig => twig.updateFoliageDensity());
}

storeBranchShape() {
  this.storedRotation = this.mesh.rotation.clone();
  this.storedPosition = this.mesh.position.clone();
}

restoreBranchShape() {
  if (this.storedRotation) {
    this.mesh.rotation.copy(this.storedRotation);
  }
  if (this.storedPosition) {
    this.mesh.position.copy(this.storedPosition);
  }
}

// Method to update foliage size in real time
updateFoliageSize() {
  if (!this.foliageGroup || this.isPruned) return;

  // Clear existing foliage
  while (this.foliageGroup.children.length > 0) {
    this.foliageGroup.remove(this.foliageGroup.children[0]);
  }
  
  // Recreate foliage with new size
  if (isNeedleType()) {
    this.createNeedles();
  } else {
    this.createDeciduousLeaves();
  }

  // Twigs carry their own foliage but aren't in tree.branches; recurse so their
  // size updates too.
  if (this.twigs) this.twigs.forEach(twig => twig.updateFoliageSize());
}

updateLeafColors() {
  if (this.instancedLeaves) {
    const geom = this.instancedLeaves.geometry;
    const palette = leafPalette();
    const gradient = paletteIsGradient(palette);
    // The ramp may be missing if this leaf was first built with a flat palette and
    // the user has just switched to a gradient one; add it on demand.
    if (gradient && !geom.attributes.aGrad) addLeafGradientRamp(geom);
    const arr = geom.attributes.instanceColor.array;
    const arr2 = geom.attributes.instanceColor2.array;
    for (let i = 0; i < this.instancedLeaves.count; i++) {
      const [lo, hi] = pickLeafColors(palette, gradient);
      const o = i * 3;
      arr[o] = lo.r; arr[o + 1] = lo.g; arr[o + 2] = lo.b;
      arr2[o] = hi.r; arr2[o + 1] = hi.g; arr2[o + 2] = hi.b;
    }
    geom.attributes.instanceColor.needsUpdate = true;
    geom.attributes.instanceColor2.needsUpdate = true;
  }

  // Twigs carry their own foliage but aren't in tree.branches; recurse so their
  // leaves recolor too.
  if (this.twigs) this.twigs.forEach(twig => twig.updateLeafColors());
}

      createBranchGeometry() {
  // Create curved branch with low poly aesthetic
  const curve = new THREE.QuadraticBezierCurve3(
    new THREE.Vector3(0, 0, 0),
    new THREE.Vector3(this.length * 0.5, this.length * 0.3, 0),
    new THREE.Vector3(this.length, this.length * 0.2, 0)
  );

  this.curve = curve;

  // LOW POLY
  const branchGeometry = new THREE.TubeGeometry(curve, BRANCH_TUBULAR_SEGMENTS, this.thickness, BRANCH_RADIAL_SEGMENTS);
  this._applyBarkColors(branchGeometry);

  const branchMaterial = new THREE.MeshStandardMaterial({
    vertexColors: true,
    roughness: 0.8,
    metalness: 0.1,
    flatShading: true, // LOW POLY: Enable flat shading
    //two sided: true
    side: THREE.DoubleSide
  });

  const branchMesh = new THREE.Mesh(branchGeometry, branchMaterial);
  branchMesh.castShadow = true;
  branchMesh.receiveShadow = true;
  branchMesh.userData.branch = this;

  this.mesh.add(branchMesh);
  this.branchMesh = branchMesh;
  this.tipRing = BRANCH_TUBULAR_SEGMENTS; // current tip; shrinks as the branch is partially pruned
  this.tubeParams = {
    radialSegments: BRANCH_RADIAL_SEGMENTS,
    tubularSegments: BRANCH_TUBULAR_SEGMENTS
  };
}

// Write the bark gradient into a tube geometry's vertex `color` attribute.
// Shared by the full branch and the truncated stub rebuilt on a partial prune.
_applyBarkColors(geometry) {
  const colors = [];
  const positions = geometry.attributes.position;
  const baseColor = new THREE.Color(parameters.truncColor);

  for (let i = 0; i < positions.count; i++) {
    const lengthRatio = positions.getZ(i) / this.length;
    const color = baseColor.clone();
    color.offsetHSL(0, 0, lengthRatio * 0.15);
    applyBirchBand(color, positions, i, lengthRatio, 'z');

    colors.push(color.r, color.g, color.b);
  }

  geometry.setAttribute('color', new THREE.BufferAttribute(new Float32Array(colors), 3));
}

// --- Partial pruning -------------------------------------------------------
// A branch is a tube of BRANCH_TUBULAR_SEGMENTS segments along this.curve.
// Hovering highlights everything past the nearest ring in red (previewCut);
// clicking lops that part off, keeping the stub up to the ring (cutAt). The
// very base always keeps at least one segment; hovering the tip cuts nothing.

// World-space hit point -> the ring index to cut at: 0 removes the whole
// branch, tipRing-1 removes just the last segment. Always returns a removable
// ring so pointing anywhere on the branch cuts from there outward.
cutRingForPoint(worldPoint) {
  this.mesh.updateWorldMatrix(true, false);
  const local = this.mesh.worldToLocal(worldPoint.clone());

  // Nearest point on the (baked, un-bent) curve, sampled finely.
  let bestT = 0;
  let bestDist = Infinity;
  const SAMPLES = 40;
  for (let i = 0; i <= SAMPLES; i++) {
    const t = i / SAMPLES;
    const d = this.curve.getPoint(t).distanceToSquared(local);
    if (d < bestDist) { bestDist = d; bestT = t; }
  }

  // Snap to a ring, biased so a segment starts pruning once the cursor is ~20%
  // in from its tip edge (a plain round waits for the 50% midpoint), so cuts
  // trigger sooner as you move down a segment.
  const ring = Math.floor(bestT * BRANCH_TUBULAR_SEGMENTS + 0.2);
  return THREE.MathUtils.clamp(ring, 0, this.tipRing - 1);
}

// Highlight the wood (and foliage) past `ring` red to preview what a click
// removes. The wood highlight is a separate red overlay sleeve over exactly the
// doomed segments, so the boundary is a hard edge at the cut ring — tinting the
// tube's own vertex colors would gradient across the shared seam ring.
previewCut(ring) {
  if (this._previewRing === ring) return;
  this.clearCutPreview();
  this._previewRing = ring;

  const cutT = ring / BRANCH_TUBULAR_SEGMENTS;
  const tipT = this.tipRing / BRANCH_TUBULAR_SEGMENTS;
  this._cutPreviewMesh = new THREE.Mesh(
    new THREE.TubeGeometry(
      new SubCurve(this.curve, cutT, tipT),
      this.tipRing - ring,
      this.thickness * 1.06, // just outside the wood, to avoid z-fighting
      BRANCH_RADIAL_SEGMENTS
    ),
    new THREE.MeshBasicMaterial({ color: 0xd21a1a })
  );
  this._cutPreviewMesh.raycast = () => {}; // don't intercept hover picking
  this.mesh.add(this._cutPreviewMesh);

  // Remember and recolor the foliage beyond the cut so it can be restored.
  this._foliagePreview = [];
  const cutX = this.curve.getPoint(cutT).x;
  this._eachFoliageBeyond(cutX, (item) => {
    if (item.kind === 'leaf') {
      this._foliagePreview.push({ kind: 'leaf', ref: item.ref, color: item.ref.material.color.getHex() });
      item.ref.material.color.setHex(0xd21a1a);
    } else { // needle instance
      const arr = item.ref.geometry.attributes.instanceColor.array;
      const o = item.index * 3;
      this._foliagePreview.push({ kind: 'needle', ref: item.ref, index: item.index, rgb: [arr[o], arr[o + 1], arr[o + 2]] });
      arr[o] = 0.82; arr[o + 1] = 0.1; arr[o + 2] = 0.1;
      item.ref.geometry.attributes.instanceColor.needsUpdate = true;
    }
  });

  // Twigs whose base sits past the cut would fall with it — light them up too,
  // matching which twigs cutAt() actually reparents into the debris.
  this._previewTwigs = [];
  if (this.twigs) {
    for (const twig of this.twigs) {
      if (!twig.isPruned && twig.mesh.position.x >= cutX) {
        twig.previewDoomed();
        this._previewTwigs.push(twig);
      }
    }
  }
}

// Undo a previewCut, removing the red overlay and restoring foliage colors.
clearCutPreview() {
  if (this._previewRing == null) return;

  if (this._cutPreviewMesh) {
    this.mesh.remove(this._cutPreviewMesh);
    this._cutPreviewMesh.geometry.dispose();
    this._cutPreviewMesh.material.dispose();
    this._cutPreviewMesh = null;
  }

  if (this._foliagePreview) {
    let dirtyNeedles = null;
    for (const item of this._foliagePreview) {
      if (item.kind === 'leaf') {
        item.ref.material.color.setHex(item.color);
      } else {
        const arr = item.ref.geometry.attributes.instanceColor.array;
        const o = item.index * 3;
        arr[o] = item.rgb[0]; arr[o + 1] = item.rgb[1]; arr[o + 2] = item.rgb[2];
        dirtyNeedles = item.ref;
      }
    }
    if (dirtyNeedles) dirtyNeedles.geometry.attributes.instanceColor.needsUpdate = true;
    this._foliagePreview = null;
  }

  if (this._previewTwigs) {
    this._previewTwigs.forEach(twig => twig.restoreDoomed());
    this._previewTwigs = null;
  }

  this._previewRing = null;
}

// Light up this entire branch red — used on twigs that a parent branch's cut
// would take with it, so the hover preview makes clear they're going too. The
// twig is always pruned whole, so we tint all of it: wood glows via emissive
// (each branch owns its wood material), foliage reuses the same red as the
// parent's previewCut. Idempotent; paired with restoreDoomed().
previewDoomed() {
  if (this._doomedPreview) return;

  const wood = [];
  [this.branchMesh, this.endCap].forEach(m => {
    if (m && m.material && m.material.emissive) {
      wood.push({ ref: m, emissive: m.material.emissive.getHex() });
      m.material.emissive.setHex(0xd21a1a);
    }
  });

  const foliage = [];
  this._eachFoliageBeyond(-Infinity, (item) => { // -Infinity = the whole twig
    if (item.kind === 'leaf') {
      foliage.push({ kind: 'leaf', ref: item.ref, color: item.ref.material.color.getHex() });
      item.ref.material.color.setHex(0xd21a1a);
    } else { // needle instance
      const arr = item.ref.geometry.attributes.instanceColor.array;
      const o = item.index * 3;
      foliage.push({ kind: 'needle', ref: item.ref, index: item.index, rgb: [arr[o], arr[o + 1], arr[o + 2]] });
      arr[o] = 0.82; arr[o + 1] = 0.1; arr[o + 2] = 0.1;
      item.ref.geometry.attributes.instanceColor.needsUpdate = true;
    }
  });

  this._doomedPreview = { wood, foliage };

  // Twigs growing off this branch fall with it (see cutAt/prune), so tint them
  // too — otherwise the red preview stops at the sub-branch and the player can't
  // tell the attached twigs are going as well.
  if (this.twigs) this.twigs.forEach(twig => twig.previewDoomed());
}

// Undo previewDoomed, restoring the twig's wood and foliage colors.
restoreDoomed() {
  if (this.twigs) this.twigs.forEach(twig => twig.restoreDoomed());
  if (!this._doomedPreview) return;

  this._doomedPreview.wood.forEach(w => w.ref.material.emissive.setHex(w.emissive));

  let dirtyNeedles = null;
  for (const item of this._doomedPreview.foliage) {
    if (item.kind === 'leaf') {
      item.ref.material.color.setHex(item.color);
    } else {
      const arr = item.ref.geometry.attributes.instanceColor.array;
      const o = item.index * 3;
      arr[o] = item.rgb[0]; arr[o + 1] = item.rgb[1]; arr[o + 2] = item.rgb[2];
      dirtyNeedles = item.ref;
    }
  }
  if (dirtyNeedles) dirtyNeedles.geometry.attributes.instanceColor.needsUpdate = true;
  this._doomedPreview = null;
}

// Visit each foliage element whose base sits at or beyond local-x `cutX`.
// Needles and leaves are both InstancedMeshes (visited per-instance, kind
// 'needle'); the 'leaf' kind is kept for any future per-mesh foliage.
_eachFoliageBeyond(cutX, cb) {
  if (!this.foliageGroup) return;
  const p = new THREE.Vector3();
  const m = new THREE.Matrix4();
  this.foliageGroup.children.forEach(child => {
    if (child.isInstancedMesh) {
      for (let i = 0; i < child.count; i++) {
        child.getMatrixAt(i, m);
        p.setFromMatrixPosition(m);
        if (p.x >= cutX) cb({ kind: 'needle', ref: child, index: i });
      }
    } else if (child.isMesh && child.position.x >= cutX) {
      cb({ kind: 'leaf', ref: child });
    }
  });
}

// Lop off everything past `ring` and drop it as falling debris. ring 0 removes
// the whole branch; otherwise the stub tube is rebuilt and re-capped.
// `instant` (used by save/replay) applies the same end state but discards the
// offcut immediately instead of animating it falling away.
cutAt(ring, instant = false) {
  this.clearCutPreview();
  if (ring == null || ring >= this.tipRing) return;

  // Debris shares this.mesh's local space (identity transform) so reparented
  // pieces keep their positions, then we animate the whole group away.
  const debris = new THREE.Group();
  this.mesh.add(debris);

  if (ring === 0) {
    // Whole-branch removal: hand every part to the debris and mark it pruned.
    debris.add(this.branchMesh);
    if (this.endCap) { debris.add(this.endCap); this.endCap = null; }
    [...this.foliageGroup.children].forEach(child => debris.add(child));
    // Any twigs growing off this branch fall with it.
    if (this.twigs) this.twigs.forEach(twig => { debris.add(twig.mesh); twig.isPruned = true; });
    this.isPruned = true;
    this.tipRing = 0;
  } else {
    const cutT = ring / BRANCH_TUBULAR_SEGMENTS;
    const tipT = this.tipRing / BRANCH_TUBULAR_SEGMENTS; // current tip, before this cut
    const cutX = this.curve.getPoint(cutT).x;

    // Wood: keep [0, cutT], hand the offcut [cutT, tipT] to the debris group.
    // Clone the material so fading the offcut out doesn't touch the live stub.
    const offcut = new THREE.Mesh(
      this._makeTubeGeometry(cutT, tipT, this.tipRing - ring),
      this.branchMesh.material.clone()
    );
    offcut.castShadow = true;
    debris.add(offcut);
    this.branchMesh.geometry.dispose();
    this.branchMesh.geometry = this._makeTubeGeometry(0, cutT, ring);
    this.tipRing = ring;

    // Cap: the old tip cap falls with the offcut; the fresh stub gets a new cap.
    if (this.endCap) {
      debris.add(this.endCap); // reparent keeps local coords
      this.endCap = null;
    }
    this.endCap = this._makeCap(cutT);
    if (this.endCap) this.mesh.add(this.endCap);

    // Twigs whose base sits past the cut fall with the offcut; ones on the
    // surviving stub stay put. (Twig base x is in this same curve-local space.)
    if (this.twigs) {
      this.twigs.forEach(twig => {
        if (!twig.isPruned && twig.mesh.position.x >= cutX) {
          debris.add(twig.mesh);
          twig.isPruned = true;
        }
      });
    }
    // Instanced foliage (needles and leaves) past the cut: instances can't be
    // reparented one-by-one, so each instanced mesh hands its offcut instances to
    // a falling copy and collapses them on the live stub. See _dropInstancedFoliageBeyond.
    this._dropInstancedFoliageBeyond(this.instancedNeedles, cutX, debris);
    this._dropInstancedFoliageBeyond(this.instancedLeaves, cutX, debris);
    this._dropInstancedFoliageBeyond(this.instancedSnow, cutX, debris);
  }

  // Replay path: skip the falling animation, just drop the offcut now.
  if (instant) {
    this.mesh.remove(debris);
    debris.traverse(o => { if (o.material) o.material.dispose?.(); if (o.geometry) o.geometry.dispose?.(); });
    return;
  }

  // The debris was assembled in the branch's (rotated) local space. Re-parent
  // it to the scene root with attach() — this preserves its world transform but
  // makes "down" truly world-down, so the offcut falls straight rather than
  // drifting back toward the trunk.
  let root = this.mesh;
  while (root.parent) root = root.parent;
  root.attach(debris);

  // Fall straight down and fade out. (A scale-to-zero would shrink toward the
  // debris pivot, which sits at the branch base — i.e. back toward the trunk —
  // so we fade instead of shrink.)
  const materials = [];
  debris.traverse(o => {
    if (o.material) { o.material.transparent = true; materials.push(o.material); }
  });
  gsap.to(debris.position, { y: '-=22', duration: 0.9, ease: 'power1.in' });
  gsap.to(materials, {
    opacity: 0,
    duration: 0.9,
    ease: 'power2.in',
    onComplete: () => {
      root.remove(debris);
      materials.forEach(m => m.dispose());
    }
  });
}

// Hand an instanced foliage mesh's offcut (instances whose base sits past local-x
// `cutX`) to the falling `debris`. Instances can't be reparented one at a time, so
// we make a copy that keeps only the doomed instances (the rest collapsed to zero
// scale) and collapse those same instances on the live stub. The copy shares the
// geometry (so per-instance colors come along) but clones the material so fading
// the offcut doesn't touch the survivors. No-op when there's nothing to drop.
_dropInstancedFoliageBeyond(live, cutX, debris) {
  if (!live) return;
  const fall = new THREE.InstancedMesh(live.geometry, live.material.clone(), live.count);
  fall.material.onBeforeCompile = live.material.onBeforeCompile;
  fall.material.needsUpdate = true;
  fall.castShadow = true;
  const m = new THREE.Matrix4();
  const p = new THREE.Vector3();
  const collapsed = new THREE.Matrix4().makeScale(0, 0, 0);
  let dirty = false;
  for (let i = 0; i < live.count; i++) {
    live.getMatrixAt(i, m);
    p.setFromMatrixPosition(m);
    if (p.x >= cutX) {
      fall.setMatrixAt(i, m);         // keep in the falling copy
      live.setMatrixAt(i, collapsed); // remove from the surviving stub
      dirty = true;
    } else {
      fall.setMatrixAt(i, collapsed); // not part of the offcut
    }
  }
  fall.instanceMatrix.needsUpdate = true;
  if (dirty) {
    live.instanceMatrix.needsUpdate = true;
    debris.add(fall);
  }
}

// Build a bark-colored tube over the curve slice [t0, t1] with `tubSegs` segments.
_makeTubeGeometry(t0, t1, tubSegs) {
  const geom = new THREE.TubeGeometry(
    new SubCurve(this.curve, t0, t1),
    Math.max(tubSegs, 1),
    this.thickness,
    BRANCH_RADIAL_SEGMENTS
  );
  this._applyBarkColors(geom);
  return geom;
}

// Add foliage to the branch
addFoliage() {
  this.foliageGroup = new THREE.Group();
  
  if (isNeedleType()) {
    this.createNeedles();
  } else {
    this.createDeciduousLeaves();
  }
  
  this.mesh.add(this.foliageGroup);
}

// Dispatch a needled (conifer) foliage build to the right style. Both styles set
// this.instancedNeedles / this.needlesPerCluster, so recolor + prune work the same.
createNeedles() {
  if (parameters.leafType === 'candle') this.createCandleNeedles();
  else this.createPineNeedles();
}

// Upswept long-needle "candle": each cluster is a brush of slim, pointed needles
// fanning out of a common base in a cone that sweeps forward toward the branch
// tip and tilts up — the soft, directional look of new pine candle growth, vs the
// short flat tufts of createPineNeedles. Shares the needle color/wind/prune
// machinery (instancedNeedles + needlesPerCluster) with the classic style.
createCandleNeedles() {
  this.instancedLeaves = null;
  this.instancedSnow = null;

  // Cluster count mirrors classic pine; the brush itself is denser per cluster.
  const numClusters = Math.floor(4 + parameters.foliageDensity * 0.5 + this.length * 0.1);
  const finalClusterCount = Math.max(Math.min(numClusters, 30), 2);
  const needlesPerCluster = Math.floor(8 + parameters.foliageDensity * 0.35);
  const totalNeedles = finalClusterCount * needlesPerCluster;
  this.needlesPerCluster = needlesPerCluster;

  // Slim, long, finely pointed needle (vs the stubby taper of classic pine).
  const needleLength = 5.5 * (parameters.foliageSize / 15);
  const needleWidth = 0.16;
  const needleGeometry = new THREE.CylinderGeometry(needleWidth, needleWidth * 0.04, needleLength, 3, 1);
  needleGeometry.translate(0, needleLength / 2, 0); // base at origin, tip toward +Y

  const colorPalette = parameters.foliageColor === "greens" ? "pine" : parameters.foliageColor;
  const paletteColors = Colors[colorPalette] || Colors.pine;

  const needleMaterial = new THREE.MeshStandardMaterial({
    color: 0xffffff, roughness: 0.8, metalness: 0.1, flatShading: true, side: THREE.DoubleSide
  });

  const instancedNeedles = new THREE.InstancedMesh(needleGeometry, needleMaterial, totalNeedles);
  const instanceColors = new Float32Array(totalNeedles * 3);

  const dummy = new THREE.Object3D();
  const quat = new THREE.Quaternion();
  const Y_AXIS = new THREE.Vector3(0, 1, 0);
  let instanceIndex = 0;

  // Keep candles on the part of the branch that still exists, bunched toward the
  // outer end like the pine pad.
  const tipFraction = this.tipRing / BRANCH_TUBULAR_SEGMENTS;
  const PAD_START = 0.25;
  const CONE = Math.PI * 0.30; // brush splay half-angle (~54°)

  for (let clusterIdx = 0; clusterIdx < finalClusterCount; clusterIdx++) {
    const t = (PAD_START + (1 - PAD_START) * (clusterIdx + Math2.random() * 0.5) / finalClusterCount) * tipFraction;
    const curvePoint = this.curve.getPoint(t);
    const forward = this.curve.getTangent(t).normalize(); // toward the branch tip

    // Branch "up": world-up projected off the branch axis. The candle base lifts
    // off the surface along it and the brush axis tilts up toward it (upswept).
    const up = Y_AXIS.clone().addScaledVector(forward, -Y_AXIS.dot(forward));
    if (up.lengthSq() < 1e-4) up.set(1, 0, 0);
    up.normalize();
    const base = curvePoint.clone().addScaledVector(up, this.thickness * 0.5);
    const axis = forward.clone().addScaledVector(up, 0.35).normalize();

    // Two perpendiculars to the brush axis, to splay needles around it.
    const u = new THREE.Vector3().crossVectors(axis, Y_AXIS);
    if (u.lengthSq() < 1e-4) u.set(1, 0, 0);
    u.normalize();
    const v = new THREE.Vector3().crossVectors(axis, u).normalize();

    const baseColor = new THREE.Color(paletteColors[Math.floor(Math2.random() * paletteColors.length)]);

    for (let needleIdx = 0; needleIdx < needlesPerCluster; needleIdx++) {
      // Direction within the cone: sqrt() pushes more needles toward the rim so
      // the candle flares like a brush rather than a tight spike.
      const phi = CONE * Math.sqrt(Math2.random());
      const theta = Math2.random() * Math.PI * 2;
      const dir = axis.clone().multiplyScalar(Math.cos(phi))
        .addScaledVector(u, Math.sin(phi) * Math.cos(theta))
        .addScaledVector(v, Math.sin(phi) * Math.sin(theta))
        .normalize();

      // Spread the bases a little along the axis (a short stem) and off it, so the
      // needles emerge from a candle body instead of one point.
      dummy.position.copy(base)
        .addScaledVector(axis, Math2.random() * needleLength * 0.18)
        .addScaledVector(u, (Math2.random() - 0.5) * this.thickness * 0.3)
        .addScaledVector(v, (Math2.random() - 0.5) * this.thickness * 0.3);
      quat.setFromUnitVectors(Y_AXIS, dir);
      dummy.quaternion.copy(quat);
      dummy.scale.set(1, 0.85 + Math2.random() * 0.4, 1); // per-needle length variation
      dummy.updateMatrix();
      instancedNeedles.setMatrixAt(instanceIndex, dummy.matrix);

      const needleColor = baseColor.clone();
      needleColor.offsetHSL((Math2.random() - 0.5) * 0.12, (Math2.random() - 0.5) * 0.25, (Math2.random() - 0.5) * 0.35);
      const ci = instanceIndex * 3;
      instanceColors[ci] = needleColor.r; instanceColors[ci + 1] = needleColor.g; instanceColors[ci + 2] = needleColor.b;
      instanceIndex++;
    }
  }

  needleGeometry.setAttribute('instanceColor', new THREE.InstancedBufferAttribute(instanceColors, 3));
  injectFoliageShader(needleMaterial); // per-instance color + shared wind sway
  instancedNeedles.instanceMatrix.needsUpdate = true;
  instancedNeedles.castShadow = true;
  instancedNeedles.receiveShadow = false;
  instancedNeedles.raycast = () => {}; // let prune/shape clicks pass through to wood
  this.foliageGroup.add(instancedNeedles);
  this.instancedNeedles = instancedNeedles;
}

// Create pine needle clusters
createPineNeedles() {
  // This branch is now needled, not leaved — drop any stale leaf reference so
  // the prune path doesn't try to shed leaves that aren't here.
  this.instancedLeaves = null;

  // 'none' (Bare / Winter): snow, not needles. (Reached only if something routes
  // a bare tree here; the normal path sends 'none' to createDeciduousLeaves.)
  if (parameters.leafType === 'none') { this.createSnow(); return; }
  this.instancedSnow = null; // needled branch: clear any winter-snow reference

  // Calculate clusters based on foliageDensity parameter
  const baseClusterCount = 4; // Reduced base count
  const clustersPerDensityUnit = parameters.foliageDensity * 0.5; // Use density parameter
  const lengthFactor = this.length * 0.1; // Branch length influence
  const numClusters = Math.floor(baseClusterCount + clustersPerDensityUnit + lengthFactor);
  const maxClusters = Math.min(numClusters, 30); // Reasonable maximum
  const finalClusterCount = Math.max(maxClusters, 2); // Minimum of 2 clusters
  
  // ~5 needles per tuft (a realistic pine fascicle), scaling only gently with
  // density — at the default density of 18 this lands on 5.
  const needlesPerCluster = Math.floor(3 + (parameters.foliageDensity * 0.12));
  const totalNeedles = finalClusterCount * needlesPerCluster;

  // Remember the real layout so updateNeedleColors recolors every cluster
  // exactly (a stale hardcoded count leaves trailing needles the old color).
  this.needlesPerCluster = needlesPerCluster;

  // Short like classic pine, but as slim and finely pointed as the candle needle —
  // the thin profile is what gives the better, less-plastic look.
  const needleLength = 3.5 * (parameters.foliageSize / 15);
  const needleWidth = 0.16;

  const needleGeometry = new THREE.CylinderGeometry(
    needleWidth,
    needleWidth * 0.04,
    needleLength,
    3, // Low poly
    1
  );
  
  // Move base to origin
  needleGeometry.translate(0, needleLength / 2, 0);

  // Get colors from palette
  const colorPalette = parameters.foliageColor === "greens" ? "pine" : parameters.foliageColor;
  const paletteColors = Colors[colorPalette] || Colors.pine;

  // Create material
  const needleMaterial = new THREE.MeshStandardMaterial({
    color: 0xffffff, // White base
    roughness: 0.8,
    metalness: 0.1,
    flatShading: true,
    side: THREE.DoubleSide
  });

  // Create instanced mesh
  const instancedNeedles = new THREE.InstancedMesh(
    needleGeometry,
    needleMaterial,
    totalNeedles
  );

  // Create array for per-needle colors
  const instanceColors = new Float32Array(totalNeedles * 3);

  // Position instances
  const dummy = new THREE.Object3D();
  let instanceIndex = 0;

  // Keep foliage on the part of the branch that still exists: a partially
  // pruned branch only spans [0, tipFraction] of the original curve.
  const tipFraction = this.tipRing / BRANCH_TUBULAR_SEGMENTS;

  // Concentrate the needle clusters toward the outer end so the canopy reads as
  // a rounded bonsai foliage pad rather than fuzz running the whole branch.
  const PAD_START = 0.3;
  const Y_AXIS = new THREE.Vector3(0, 1, 0);
  const quat = new THREE.Quaternion();
  const CONE = Math.PI * 0.34; // tuft splay half-angle (~61°): an upward fan, kept tight

  for (let clusterIdx = 0; clusterIdx < finalClusterCount; clusterIdx++) {
    const t = (PAD_START + (1 - PAD_START) * (clusterIdx + 0.2) / finalClusterCount) * tipFraction;
    const curvePoint = this.curve.getPoint(t);
    const tangent = this.curve.getTangent(t).normalize();

    // Needles point mostly UP — the upright pads of a classic bonsai. The tuft
    // splays around world-up (with a slight lean toward the branch tip and a small
    // random tilt for variety), NOT around the branch, so needles fan upward
    // instead of wrapping onto the sides and underside.
    const side = new THREE.Vector3().crossVectors(tangent, Y_AXIS);
    if (side.lengthSq() < 1e-4) side.set(1, 0, 0);
    side.normalize();
    const axis = Y_AXIS.clone()
      .addScaledVector(tangent, 0.2)                 // gentle lean toward the tip
      .addScaledVector(side, (Math2.random() - 0.5) * 0.5) // small per-tuft tilt off vertical
      .normalize();

    // Seat the tuft on the upper side of the branch.
    const topNormal = Y_AXIS.clone().addScaledVector(tangent, -Y_AXIS.dot(tangent));
    if (topNormal.lengthSq() < 1e-4) topNormal.set(1, 0, 0);
    topNormal.normalize();
    const base = curvePoint.clone().addScaledVector(topNormal, this.thickness * 0.5);

    // Two perpendiculars to the tuft axis, to splay needles around it.
    const u = new THREE.Vector3().crossVectors(axis, Y_AXIS);
    if (u.lengthSq() < 1e-4) u.set(1, 0, 0);
    u.normalize();
    const v = new THREE.Vector3().crossVectors(axis, u).normalize();

    const baseColor = new THREE.Color(paletteColors[Math.floor(Math2.random() * paletteColors.length)]);

    for (let needleIdx = 0; needleIdx < needlesPerCluster; needleIdx++) {
      // Splay within a cone; sqrt() biases needles toward the rim for a full,
      // rounded tuft rather than a sparse centre.
      const phi = CONE * Math.sqrt(Math2.random());
      const theta = Math2.random() * Math.PI * 2;
      const dir = axis.clone().multiplyScalar(Math.cos(phi))
        .addScaledVector(u, Math.sin(phi) * Math.cos(theta))
        .addScaledVector(v, Math.sin(phi) * Math.sin(theta))
        .normalize();

      // Emerge from a small tuft body, not a single point.
      dummy.position.copy(base)
        .addScaledVector(axis, Math2.random() * needleLength * 0.15)
        .addScaledVector(u, (Math2.random() - 0.5) * this.thickness * 0.25)
        .addScaledVector(v, (Math2.random() - 0.5) * this.thickness * 0.25);
      quat.setFromUnitVectors(Y_AXIS, dir);
      dummy.quaternion.copy(quat);
      dummy.scale.set(1, 0.8 + Math2.random() * 0.4, 1); // per-needle length variation
      dummy.updateMatrix();
      instancedNeedles.setMatrixAt(instanceIndex, dummy.matrix);

      const needleColor = baseColor.clone();
      needleColor.offsetHSL(
        (Math2.random() - 0.5) * 0.12, // Slight hue shift
        (Math2.random() - 0.5) * 0.25, // Saturation variation
        (Math2.random() - 0.5) * 0.35  // Brightness variation
      );
      const colorIndex = instanceIndex * 3;
      instanceColors[colorIndex] = needleColor.r;
      instanceColors[colorIndex + 1] = needleColor.g;
      instanceColors[colorIndex + 2] = needleColor.b;

      instanceIndex++;
    }
  }

  // Add instance colors to geometry
  needleGeometry.setAttribute('instanceColor', 
    new THREE.InstancedBufferAttribute(instanceColors, 3)
  );

  // Per-instance color + wind sway (shared with deciduous leaves).
  injectFoliageShader(needleMaterial);

  // Update all matrices
  instancedNeedles.instanceMatrix.needsUpdate = true;
  
  // Enable shadows
  instancedNeedles.castShadow = true;
  instancedNeedles.receiveShadow = false;

  // Ignore needles when picking so pruning clicks pass through to the wood.
  instancedNeedles.raycast = () => {};

  // Add to branch
  this.foliageGroup.add(instancedNeedles);
  
  // Store reference for updates
  this.instancedNeedles = instancedNeedles;
}

updateNeedleColors() {
  if (!this.instancedNeedles) {
    // No needles on this branch, but its twigs may carry their own.
    if (this.twigs) this.twigs.forEach(twig => twig.updateNeedleColors());
    return;
  }

  const colorPalette = parameters.foliageColor === "greens" ? "pine" : parameters.foliageColor;
  const paletteColors = Colors[colorPalette] || Colors.pine;
  
  const instanceColors = this.instancedNeedles.geometry.attributes.instanceColor.array;
  // Use the same per-cluster count the needles were built with so every
  // instance (including the last cluster) gets recolored.
  const needlesPerCluster = this.needlesPerCluster || 10;

  let instanceIndex = 0;
  const numClusters = Math.floor(this.instancedNeedles.count / needlesPerCluster);
  
  for (let clusterIdx = 0; clusterIdx < numClusters; clusterIdx++) {
    // Pick new base color for this cluster
    const baseColorHex = paletteColors[Math.floor(Math2.random() * paletteColors.length)];
    const baseColor = new THREE.Color(baseColorHex);
    
    // Update all needles in this cluster
    for (let needleIdx = 0; needleIdx < needlesPerCluster; needleIdx++) {
      const needleColor = baseColor.clone();
      needleColor.offsetHSL(
        (Math2.random() - 0.5) * 0.12,
        (Math2.random() - 0.5) * 0.25,
        (Math2.random() - 0.5) * 0.35
      );
      
      const colorIndex = instanceIndex * 3;
      instanceColors[colorIndex] = needleColor.r;
      instanceColors[colorIndex + 1] = needleColor.g;
      instanceColors[colorIndex + 2] = needleColor.b;
      
      instanceIndex++;
    }
  }
  
  // Mark for update
  this.instancedNeedles.geometry.attributes.instanceColor.needsUpdate = true;

  // Twigs carry their own needles but aren't in tree.branches; recurse so they
  // recolor too.
  if (this.twigs) this.twigs.forEach(twig => twig.updateNeedleColors());
}

// Create deciduous leaves
createDeciduousLeaves() {
  // This branch is now leaved, not needled — drop any stale needle reference so
  // the prune path doesn't try to shed needles that aren't here.
  this.instancedNeedles = null;

  // 'none' (Bare / Winter): no leaves — drape snow along the bare branch instead
  // (createSnow clears the leaf/needle refs). The exposed structure stays easy to
  // prune since the snow ignores picking.
  if (parameters.leafType === 'none') { this.createSnow(); return; }
  this.instancedSnow = null; // leafed branch: clear any winter-snow reference

  // Calculate leaf count based on foliageDensity parameter
  const baseLeafCount = 3;
  const densityFactor = parameters.foliageDensity * 0.8; // Use density parameter
  const lengthFactor = this.length * 0.05; // Branch length influence
  const leafCount = Math.floor(baseLeafCount + densityFactor + lengthFactor);
  const maxLeaves = Math.min(leafCount, 25); // Reasonable maximum
  const finalLeafCount = Math.max(maxLeaves, 2); // Minimum of 2 leaves

  const sizeScale = parameters.foliageSize / 15;

  // One leaf geometry shared by every instance on this branch; per-leaf variety
  // comes from the instance matrix (position/rotation/scale) and instanceColor.
  const leafGeometry = this._makeLeafGeometry();

  const leafMaterial = new THREE.MeshStandardMaterial({
    color: 0xffffff, // base white; tinted per-instance via instanceColor
    roughness: 0.7,
    metalness: 0.1,
    flatShading: true,
    side: THREE.DoubleSide,
    transparent: true,
    opacity: 0.9,
    // Cherry blossoms carry a per-vertex centre gradient; other leaf geometries
    // have no color attribute, so vertex colors stay off for them.
    vertexColors: parameters.leafType === 'cherry'
  });
  // Per-instance color + wind sway (shared with pine needles).
  injectFoliageShader(leafMaterial);

  const leaves = new THREE.InstancedMesh(leafGeometry, leafMaterial, finalLeafCount);
  // Two per-instance colors: base (at the petiole) and tip. For flat palettes both
  // hold the same color so the leaf reads as a single tint; gradient palettes
  // (autumn) blend base→tip along the per-vertex ramp added below.
  const palette = leafPalette();
  const gradient = paletteIsGradient(palette);
  const instanceColors = new Float32Array(finalLeafCount * 3);
  const instanceColors2 = new Float32Array(finalLeafCount * 3);

  // Keep leaves on the part of the branch that still exists: a partially
  // pruned branch only spans [0, tipFraction] of the original curve.
  const tipFraction = this.tipRing / BRANCH_TUBULAR_SEGMENTS;
  const dummy = new THREE.Object3D();

  // Foliage pad: real bonsai bunch their leaves into a rounded mass on the outer
  // end of each branch. Each leaf attaches to the branch surface by its stem and
  // the blade hangs out at the end of that stem, so successive leaves splay all
  // the way around the branch instead of clumping into one blob.
  const PAD_START = 0.4;
  const Y_AXIS = new THREE.Vector3(0, 1, 0);
  const quat = new THREE.Quaternion();

  for (let i = 0; i < finalLeafCount; i++) {
    // Step along the outer pad, with a little jitter so leaves don't ring up.
    const t = (PAD_START + (1 - PAD_START) * ((i + Math2.random() * 0.6) / finalLeafCount)) * tipFraction;
    const curvePoint = this.curve.getPoint(t);
    const tangent = this.curve.getTangent(t).normalize();

    // "Up" around the branch: world-up projected into the plane perpendicular to
    // the branch (the top of the branch). Leaves fan around the top and sides
    // from here but stay off the underside, the way needles do — so the clock
    // angle is restricted to leave a clear arc on the bottom.
    const normal = Y_AXIS.clone().addScaledVector(tangent, -Y_AXIS.dot(tangent));
    if (normal.lengthSq() < 1e-4) normal.set(1, 0, 0); // ~vertical branch: any perp
    normal.normalize();
    const UNDERSIDE_GAP = Math.PI * 0.7;               // bare arc on the underside
    const clock = (Math2.random() - 0.5) * (Math.PI * 2 - UNDERSIDE_GAP);
    normal.applyAxisAngle(tangent, clock);

    // Aim: leaves near the branch base point straight out (radial), but the
    // further out along the pad they sit, the more they lean toward the tip
    // direction (the tangent) — so the canopy points away from the trunk at the
    // ends instead of bristling sideways.
    const outward = (t / tipFraction - PAD_START) / (1 - PAD_START); // 0 at pad start → 1 at tip
    const aim = normal.clone().addScaledVector(tangent, outward * 1.3).normalize();

    // Stem base sits just off the branch surface (offset along the radial normal);
    // the stem (+Y in the geometry) follows `aim`, then we spin the blade around
    // the stem and add a gentle droop.
    dummy.position.copy(curvePoint).addScaledVector(normal, this.thickness * 0.85);
    quat.setFromUnitVectors(Y_AXIS, aim);
    dummy.quaternion.copy(quat);
    dummy.rotateY(Math2.random() * Math.PI * 2);   // spin the blade around its stem
    dummy.rotateX((Math2.random() - 0.5) * 0.8);   // gentle droop
    dummy.scale.setScalar((0.8 + Math2.random() * 0.4) * sizeScale);
    dummy.updateMatrix();
    leaves.setMatrixAt(i, dummy.matrix);

    const [lo, hi] = pickLeafColors(palette, gradient);
    const o = i * 3;
    instanceColors[o] = lo.r; instanceColors[o + 1] = lo.g; instanceColors[o + 2] = lo.b;
    instanceColors2[o] = hi.r; instanceColors2[o + 1] = hi.g; instanceColors2[o + 2] = hi.b;
  }

  if (gradient) addLeafGradientRamp(leafGeometry);
  leafGeometry.setAttribute('instanceColor', new THREE.InstancedBufferAttribute(instanceColors, 3));
  leafGeometry.setAttribute('instanceColor2', new THREE.InstancedBufferAttribute(instanceColors2, 3));
  leaves.instanceMatrix.needsUpdate = true;
  leaves.castShadow = true;
  // Ignore leaves when picking so pruning clicks pass through to the wood.
  leaves.raycast = () => {};
  // Marks this as sheddable foliage for the autumn leaf-fall (see updateLeafFall).
  leaves.userData.isLeaf = true;

  this.foliageGroup.add(leaves);
  this.instancedLeaves = leaves;
}

// Snow / frost for 'none' (Bare / Winter) mode: small white clumps draped along
// the TOP of the bare branch. Built like the leaf canopy — one InstancedMesh per
// branch, placed from the seeded Math2 stream so saves replay identically — but
// with NO wind sway (snow sits frozen, so it skips injectFoliageShader) and a
// faint blue emissive so shadowed sides read as frost. It lives in foliageGroup,
// so the existing prune machinery carries it for free: whole-branch cuts drop it
// with the branch, partial cuts shed the clumps past the cut, and the hover
// preview recolors it — that last path reads an instanceColor attribute off every
// instanced foliage child, so we add one (white) even though the snow material
// ignores the value.
createSnow() {
  this.instancedNeedles = null;
  this.instancedLeaves = null;

  const tipFraction = this.tipRing / BRANCH_TUBULAR_SEGMENTS;
  // More clumps on longer branches and at higher foliage density; clamped. Run it
  // dense so neighbouring clumps overlap into a continuous ridge of snow rather
  // than separate plops.
  const count = Math.max(3, Math.min(
    Math.floor(this.length * 0.22 + parameters.foliageDensity * 0.5), 38));
  // Clumps scale with branch thickness, nudged by the foliage-size slider so that
  // control stays meaningful in winter mode.
  const sizeScale = 0.7 + (parameters.foliageSize / 15) * 0.5;

  const snowGeometry = new THREE.IcosahedronGeometry(1, 0); // faceted low-poly clump
  const snowMaterial = new THREE.MeshStandardMaterial({
    color: 0xeef4ff,        // cool white
    roughness: 0.95,
    metalness: 0.0,
    flatShading: true,      // keep the faceted low-poly look
    emissive: 0x2a3f5f,     // faint blue frost in shadow
    emissiveIntensity: 0.15
  });

  const snow = new THREE.InstancedMesh(snowGeometry, snowMaterial, count);
  const Y_AXIS = new THREE.Vector3(0, 1, 0);
  const dummy = new THREE.Object3D();
  const quat = new THREE.Quaternion();
  const SNOW_START = 0.05; // skip the very base where the branch meets its parent

  for (let i = 0; i < count; i++) {
    // Walk from just past the base to the surviving tip.
    const t = SNOW_START + (tipFraction - SNOW_START) * ((i + Math2.random() * 0.7) / count);
    const curvePoint = this.curve.getPoint(t);
    const tangent = this.curve.getTangent(t).normalize();

    // Top of the branch: world-up projected perpendicular to the branch, then a
    // small clock jitter so clumps settle near the upper surface (where snow
    // lands) rather than ringing all the way around.
    const normal = Y_AXIS.clone().addScaledVector(tangent, -Y_AXIS.dot(tangent));
    if (normal.lengthSq() < 1e-4) normal.set(1, 0, 0); // ~vertical branch: any perp
    normal.normalize();
    normal.applyAxisAngle(tangent, (Math2.random() - 0.5) * 0.7); // pile near the top

    // Seat the clump on the branch surface; flatten axis (geometry +Y) points up
    // off the wood so it drapes as a cap rather than a ball.
    dummy.position.copy(curvePoint).addScaledVector(normal, this.thickness * 0.6);
    quat.setFromUnitVectors(Y_AXIS, normal);
    dummy.quaternion.copy(quat);
    dummy.rotateY(Math2.random() * Math.PI * 2); // random spin so clumps differ
    // Wide and fairly thick so clumps overlap into one snowy mass on the branch.
    const r = this.thickness * (1.35 + Math2.random() * 0.5) * sizeScale;
    dummy.scale.set(r, r * 0.7, r);
    dummy.updateMatrix();
    snow.setMatrixAt(i, dummy.matrix);
  }

  // White instanceColor so the cut hover-preview (which writes .array on every
  // instanced foliage child) has an attribute to touch; the material ignores it.
  const white = new Float32Array(count * 3).fill(1);
  snowGeometry.setAttribute('instanceColor', new THREE.InstancedBufferAttribute(white, 3));

  snow.instanceMatrix.needsUpdate = true;
  snow.castShadow = true;
  snow.raycast = () => {}; // let prune clicks pass through to the wood
  this.foliageGroup.add(snow);
  this.instancedSnow = snow;
}

// Build the foliage geometry for the current leaf type. Pine is handled
// elsewhere (needles); every other type produces one merged buffer (so it's a
// single instanced draw) whose attachment is at the local origin, with the body
// extending up +Y. Pinnate types (deciduous, willow) use the blade builder;
// maple and cherry build radial geometry.
_makeLeafGeometry() {
  if (parameters.leafType === 'maple') return this._makeMapleGeometry();
  if (parameters.leafType === 'cherry') return this._makeBlossomGeometry();
  return this._makeBladeGeometry(LEAF_SHAPES[parameters.leafType] || LEAF_SHAPES.deciduous);
}

// A thin low-poly cone petiole/pedicel from the attachment point (origin) up to
// `length`, tapering to a point. Non-indexed so it merges with the (non-indexed)
// leaf bodies. `radius` is the wide end, at the branch.
_makeStemCone(length, radius) {
  const g = new THREE.CylinderGeometry(0, radius, length, 5, 1).toNonIndexed();
  g.translate(0, length / 2, 0);
  return g;
}

// Pinnate blade (deciduous/willow): a symmetric silhouette with a serrate margin
// whose teeth point toward the tip, folded along a raised central midrib, on a
// cone petiole. `cfg` (from LEAF_SHAPES) sets the proportions and tooth profile.
_makeBladeGeometry(cfg) {
  const base = 2.25 * (parameters.foliageSize / 15);
  const len = base * cfg.length;
  const bladeBaseY = len * 0.15;     // blade slid down close to the attachment
  const stemRadius = base * 0.025;   // petiole thickness
  const halfMax = len * 0.34 * cfg.width;
  // Smooth half-width profile (clamped so a tip-skewed tooth can't run past s=1).
  const hw = (s) => halfMax * Math.pow(Math.sin(Math.PI * Math.min(Math.max(s, 0), 1)), 0.75);

  const right = []; // right-edge points [x, y], base -> tip
  for (let k = 0; k < cfg.teeth; k++) {
    const sN = k / cfg.teeth;                          // notch at the base side
    const sA = Math.min((k + cfg.skew) / cfg.teeth, 0.999); // apex skewed toward the tip
    if (k > 0) right.push([hw(sN) * (1 - cfg.notchIn), len * sN]);
    right.push([hw(sA) * (1 + cfg.toothOut), len * sA]);
  }

  // Folded mesh: a raised central spine (midrib) runs base->tip while each margin
  // point drops to z=0, so the cross-section is a shallow tent — a subtle crease.
  // It fades to nothing at base and tip via sin, so only the middle folds.
  const CREASE = len * cfg.crease;
  const creaseZ = (y) => CREASE * Math.sin(Math.PI * (y / len));
  const chain = [[0, 0], ...right, [0, len]]; // full right margin, base -> tip

  const positions = [];
  const uvs = [];
  const pushVert = (x, y, z) => {
    positions.push(x, y, z);
    uvs.push(0.5 + x / (2 * halfMax), y / len);
  };
  for (let j = 0; j < chain.length - 1; j++) {
    const [x0, y0] = chain[j];
    const [x1, y1] = chain[j + 1];
    const z0 = creaseZ(y0), z1 = creaseZ(y1);
    // Right half: spine (0,y,z) out to the margin (x,y,0).
    pushVert(0, y0, z0); pushVert(x0, y0, 0); pushVert(x1, y1, 0);
    pushVert(0, y0, z0); pushVert(x1, y1, 0); pushVert(0, y1, z1);
    // Left half: mirror across the spine (reversed winding so it faces out).
    pushVert(0, y0, z0); pushVert(-x1, y1, 0); pushVert(-x0, y0, 0);
    pushVert(0, y0, z0); pushVert(0, y1, z1); pushVert(-x1, y1, 0);
  }

  const bladeGeom = new THREE.BufferGeometry();
  bladeGeom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  bladeGeom.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
  bladeGeom.computeVertexNormals();
  bladeGeom.translate(0, bladeBaseY, 0);

  const stemGeom = this._makeStemCone(bladeBaseY + len * 0.3, stemRadius);
  const geom = mergeGeometries([stemGeom, bladeGeom]);
  bladeGeom.dispose();
  stemGeom.dispose();
  return geom;
}

// Radial leaf body: a triangle fan from a single centre vertex out to a margin
// sampled by `radiusFn(angle)` over [a0, a1]. The fan lies in the plane spanned
// by unit axes `u` and `v` (so callers can put it in-line with the stem or
// perpendicular to it), centred at `center`. `domeFn(r, a)` offsets EVERY vertex
// (centre and rim) along the plane normal — by radius for a bowl/dome, and/or by
// angle for radial pleats/folds — rather than just dimpling the centre. `R`
// normalises UVs.
// Returns a non-indexed BufferGeometry.
_makeRadialGeometry(R, center, u, v, domeFn, a0, a1, radiusFn, SEG = 60) {
  const positions = [];
  const uvs = [];
  const n = [u[1] * v[2] - u[2] * v[1], u[2] * v[0] - u[0] * v[2], u[0] * v[1] - u[1] * v[0]]; // unit normal
  const pt = (a, r) => {
    const o = domeFn(r, a);
    return [
      center[0] + (u[0] * Math.cos(a) + v[0] * Math.sin(a)) * r + n[0] * o,
      center[1] + (u[1] * Math.cos(a) + v[1] * Math.sin(a)) * r + n[1] * o,
      center[2] + (u[2] * Math.cos(a) + v[2] * Math.sin(a)) * r + n[2] * o,
    ];
  };
  const oc = domeFn(0, a0);
  const cx = center[0] + n[0] * oc, cy = center[1] + n[1] * oc, cz = center[2] + n[2] * oc;
  for (let i = 0; i < SEG; i++) {
    const aA = a0 + (a1 - a0) * (i / SEG);
    const aB = a0 + (a1 - a0) * ((i + 1) / SEG);
    const pA = pt(aA, radiusFn(aA));
    const pB = pt(aB, radiusFn(aB));
    positions.push(cx, cy, cz); uvs.push(0.5, 0.5);
    positions.push(pA[0], pA[1], pA[2]); uvs.push(0.5 + Math.cos(aA) * 0.5, 0.5 + Math.sin(aA) * 0.5);
    positions.push(pB[0], pB[1], pB[2]); uvs.push(0.5 + Math.cos(aB) * 0.5, 0.5 + Math.sin(aB) * 0.5);
  }
  const g = new THREE.BufferGeometry();
  g.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  g.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
  g.computeVertexNormals();
  return g;
}

// Palmate Japanese maple (Acer palmatum) leaf: a 7-lobed radial body whose lobes
// are long, narrow and pointed with finely serrate margins and deeply-cut sinuses.
// The central lobe is longest; lobes shorten toward the base (a length envelope)
// so the lowest pair are small basal lobes flanking a cordate notch where the
// petiole enters. Lies in the stem plane (XY), slightly cupped, on a cone petiole.
_makeMapleGeometry() {
  const base = 2.25 * (parameters.foliageSize / 15);
  const R = base * 1.15;
  const attachY = R * 0.85;
  const LOBES = 7;
  const radiusFn = (a) => {
    const phi = a - Math.PI / 2;                              // 0 = straight up
    // cos(7φ/2) gives 7 lobes peaking at φ = 0, ±2π/7, ±4π/7, ±6π/7, with sinuses
    // (incl. one straight down). Exponent > 1 narrows each lobe to a sharp point;
    // the 0.26/0.60 split cuts the sinuses deep, as in palmatum.
    const c = Math.abs(Math.cos(LOBES * phi / 2));
    const lobe = Math.pow(c, 2.0);
    // A high-exponent spike centred on each lobe peak elongates the very tip into
    // a fine drawn-out point without fattening the body of the lobe.
    const tip = Math.pow(c, 9);
    const serr = 1 + 0.11 * Math.sin(phi * 44);              // deeper marginal teeth
    // Length envelope: central lobe longest, lobes shrink toward the base so the
    // lowest pair read as the small basal lobes of a palmate leaf.
    const env = 0.45 + 0.55 * Math.pow((1 + Math.cos(phi)) / 2, 0.6);
    // Cordate base: pull the margin in only around straight-down so the two basal
    // lobes flank a smooth rounded notch where the petiole enters (no hard V).
    let d = a + Math.PI / 2;                                  // angle from straight down
    d = Math.atan2(Math.sin(d), Math.cos(d));
    const notch = Math.exp(-(d / 0.45) * (d / 0.45));
    return R * env * (0.26 + 0.56 * lobe + 0.18 * tip) * (1 - 0.55 * notch) * serr;
  };
  // Full sweep — the cordate notch above replaces the old petiole wedge.
  const a0 = -Math.PI / 2;
  const a1 = a0 + Math.PI * 2;
  // Palmate pleat: instead of a flat disc, fold the surface radially so each lobe
  // rides up along its midrib (|cos(7φ/2)| ≈ 1) while the sinuses between lobes
  // dip the other way — the characteristic creased, folded-fan look of a maple.
  // The fold opens with radius (nothing at the centre, deepest at the tips) and a
  // mild overall centre cup keeps the heart of the leaf slightly recessed.
  const FOLD = R * 0.16;
  const domeFn = (r, a) => {
    const phi = a - Math.PI / 2;
    const ridge = Math.pow(Math.abs(Math.cos(LOBES * phi / 2)), 1.5); // 1 at midribs, 0 at sinuses
    const t = Math.min(r / R, 1);
    const pleat = (ridge - 0.5) * 2 * FOLD * Math.pow(t, 1.2);        // +FOLD midrib, -FOLD sinus
    const cup = -R * 0.05 * (1 - t);                                  // gentle centre cup
    return pleat + cup;
  };
  const body = this._makeRadialGeometry(R, [0, attachY, 0], [1, 0, 0], [0, 1, 0], domeFn, a0, a1, radiusFn, 224);
  const stemGeom = this._makeStemCone(attachY - R * 0.12, base * 0.03);
  const geom = mergeGeometries([stemGeom, body]);
  body.dispose();
  stemGeom.dispose();
  return geom;
}

// Cherry blossom: five rounded, tip-notched petals. The flower lies in the plane
// perpendicular to the stem (XZ), so the stem meets its centre at a right angle
// like a T; the centre is recessed toward the branch so the bloom cups outward,
// and a per-vertex colour gradient warms the heart of the flower.
_makeBlossomGeometry() {
  const base = 2.25 * (parameters.foliageSize / 15);
  const R = base * 0.8;
  const attachY = R * 0.9;
  // cos(5a) gives five petals; the -cos(10a) term carves a small notch into each
  // petal tip (the characteristic sakura petal) and deepens the sinuses.
  const radiusFn = (a) => R * (0.6 + 0.4 * Math.cos(5 * a) - 0.12 * Math.cos(10 * a));

  // Petals in the XZ plane (u = +X, v = +Z), perpendicular to the +Y stem. The
  // plane normal (u × v) is -Y, so a NEGATIVE dome offset lifts the petals toward
  // +Y: tips rise with radius while the centre stays put, so the bloom curls into
  // a bowl that cups upward/outward along the stem.
  const CUP = R * 0.4; // bowl depth (0 = flat flower)
  const domeFn = (r) => -CUP * Math.pow(Math.min(r / R, 1), 1.4);
  const body = this._makeRadialGeometry(R, [0, attachY, 0], [1, 0, 0], [0, 0, 1], domeFn, 0, Math.PI * 2, radiusFn);
  const stemGeom = this._makeStemCone(attachY, base * 0.022);
  const geom = mergeGeometries([stemGeom, body]);
  body.dispose();
  stemGeom.dispose();

  // Centre gradient: deep rose at the heart fading to white at the petal tips.
  // This multiplies the per-instance petal colour (vertexColors is enabled on the
  // material for cherry — see createDeciduousLeaves). Distance is measured from
  // the flower centre, so the thin stem below it reads as white.
  const pos = geom.attributes.position;
  const colors = new Float32Array(pos.count * 3);
  const accent = new THREE.Color(0xE0559A);
  const white = new THREE.Color(0xffffff);
  const tmp = new THREE.Color();
  for (let i = 0; i < pos.count; i++) {
    const dx = pos.getX(i);
    const dy = pos.getY(i) - attachY;
    const dz = pos.getZ(i);
    const tt = Math.min(Math.sqrt(dx * dx + dy * dy + dz * dz) / (R * 0.5), 1);
    tmp.copy(accent).lerp(white, tt);
    colors[i * 3] = tmp.r; colors[i * 3 + 1] = tmp.g; colors[i * 3 + 2] = tmp.b;
  }
  geom.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  return geom;
}

// Update leaf type when changed in controls
updateLeafType() {
  if (this.isPruned) return;

  if (this.foliageGroup) {
    // Clear existing foliage
    this.mesh.remove(this.foliageGroup);
    this.foliageGroup = new THREE.Group();
    
    // Create new foliage based on type
    if (isNeedleType()) {
      this.createNeedles();
    } else {
      this.createDeciduousLeaves();
    }
    
    this.mesh.add(this.foliageGroup);
  }

  // Twigs carry their own foliage but aren't in tree.branches; recurse so they
  // switch leaf type too.
  if (this.twigs) this.twigs.forEach(twig => twig.updateLeafType());
}

createEndCaps() {
  this.endCap = this._makeCap(1);
  this.mesh.add(this.endCap);
}

// Build a circular bark cap oriented to the branch curve at parameter `t`.
// Used for the original tip and for re-capping the stub after a partial prune.
_makeCap(t) {
  const capRadius = this.thickness * 0.9;
  const capGeometry = new THREE.CircleGeometry(capRadius, 8);

  const point = this.curve.getPoint(t);
  const tangent = this.curve.getTangent(t);

  const capMaterial = new THREE.MeshStandardMaterial({
    color: new THREE.Color(parameters.truncColor).offsetHSL(0, -0.1, 0.3),
    roughness: 0.7,
    metalness: 0.1,
    flatShading: true
  });

  const cap = new THREE.Mesh(capGeometry, capMaterial);
  cap.userData.isEndCap = true; // so updateTrunkColor paths can recolor it by reference
  cap.position.copy(point);
  cap.lookAt(point.clone().add(tangent));
  cap.castShadow = true;
  cap.receiveShadow = true;
  return cap;
}

//PRUNE
      prune() {
        if (!this.isPruned) {
          this.isPruned = true;
          
          gsap.to(this.mesh.scale, {
            x: 0.01, y: 0.01, z: 0.01,
            duration: 0.8,
            ease: "power2.in",
            onComplete: () => {
              this.mesh.visible = false;
            }
          });
        }
      }
    }

export { Tree };
